                             <span className="px-2 py-1 bg-slate-200 group-hover:bg-blue-200 text-[10px] rounded font-bold text-slate-500 group-hover:text-blue-600">{occurrences}</span>
                          </div>
                        );
                      })}
                 </div>
               </div>

               {/* Right: Specific Phrases Container */}
               <div className="flex-1 bg-slate-50/50 p-8 overflow-y-auto">
                 <div className="max-w-3xl mx-auto space-y-8 text-center py-20">
