import { GoogleGenAI, Type } from "@google/genai";

// Initialize the GoogleGenAI with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchSynonymsAndSuggestions = async (theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Ты - эксперт по контекстной рекламе (Google Ads, Яндекс.Директ). 
    Сгенерируй максимально полный список базовых ключевых слов, синонимов и высокочастотных запросов для тематики бизнеса: "${theme}".

    Включи в список:
    1. Прямые названия услуг/товаров.
    2. Синонимы и профессиональный сленг.
    3. Слова с частыми ошибками и опечатками.
    4. Ассоциативные слова (например, для "бухгалтерии" это "налоги", "отчетность", "аутсорсинг").

    Верни ТОЛЬКО слова через запятую, без лишнего текста и нумерации. На русском языке.`,
    config: {
      temperature: 0.7,
    },
  });

  const text = response.text || "";
  // Handle various delimiters just in case
  return text.split(/[,;\n]/).map(s => s.trim()).filter(s => s.length > 0);
};

export const expandKeywords = async (baseKeywords: string[], theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Ты - профессиональный SEO и SEM эксперт с доступом к базам Google Keyword Planner, Wordstat (Yandex) и Букварикс.

    Твоя задача: собрать АБСОЛЮТНО ВСЕ возможные поисковые запросы на основе семян: ${baseKeywords.join(', ')}.
    Тематика бизнеса: "${theme}". 

    Требования к сбору:
    1. Собери все запросы, включая те, у которых частотность 0 (нулевая). 
    2. Придумай все возможные комбинации из 2, 3 и более слов (например, если семя "покраска", добавь "покраска авто цена", "покраска автомобиля в Минске недорого", "локальная покраска двери" и т.д.).
    3. Включи коммерческие добавки (купить, цена, заказать, под ключ), гео-добавки, информационные приставки.
    4. Учти опечатки, сленг и разные формы слов.
    5. НИЧЕГО НЕ ПРОПУСКАЙ. Мне нужно максимально широкое семантическое ядро.

    Верни результат в формате JSON массива строк. Только массив, без лишних пояснений.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    },
  });

  try {
    return JSON.parse(response.text || "[]") as string[];
  } catch (e) {
    console.error("Failed to parse expanded keywords", e);
    return [];
  }
};

export const smartFilterKeywords = async (keywords: string[], theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Проанализируй список ключевых слов для бизнеса в нише "${theme}":
    ${keywords.map((k, i) => `${i}: ${k}`).join('\n')}

    Определи ключевые слова, которые на 100% НЕ подходят для настройки контекстной рекламы (информационные запросы типа "бесплатно", "скачать", "реферат", запросы на поиск работы, если это не HR, и т.д.).
    КРИТИЧЕСКОЕ ПРАВИЛО: Если есть хотя бы 1% шанса, что слово целевое - НЕ выделяй его как негативное. Будь крайне осторожен.
    Верни JSON массив индексов (0-based) из предоставленного списка, которые точно являются мусорными.`,
    config: {
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.INTEGER }
      },
    },
  });

  try {
    return JSON.parse(response.text || "[]") as number[];
  } catch (e) {
    return [];
  }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  // Sync theme input with current project whenever it changes
  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set()); // Clear selection when switching projects
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;

    // Auto-create project if none exists or is selected
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      const newKeywords: Keyword[] = suggestions.map(text => ({
        id: Math.random().toString(36).substr(2, 9),
        text,
        status: 'preliminary'
      }));

      // Update directly to ensure the logic works even if activeProjectId was just set
      setProjects(prev => prev.map(p => p.id === activeProjectId ? {
        ...p,
        theme: input,
        keywords: [
          ...p.keywords.filter(k => k.status !== 'preliminary'),
          ...newKeywords
        ]
      } : p));
    } catch (e) {
      console.error(e);
      alert("Ошибка ИИ. Проверьте соединение или API ключ.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      const newKeywords: Keyword[] = expanded.map(text => ({
        id: Math.random().toString(36).substr(2, 9),
        text,
        status: 'parsed'
      }));
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...newKeywords]
      }));
      setShowSelected(false);
      setSelection(new Set());
    } catch (e) {
      console.error(e);
      alert("Ошибка при сборе запросов через ИИ.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);

    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) {
      allIds.forEach(id => currentSelection.delete(id));
    } else {
      allIds.forEach(id => currentSelection.add(id));
    }
    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);

      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = (status: KeywordStatus) => 
    currentProject?.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase())) || [];

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              ИИ анализирует...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-4 border-b border-gray-100 space-y-4">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-xs tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-xs text-red-500 hover:underline flex items-center gap-1">
                <MinusSquare size={12} /> Минус-слова
              </button>
            </div>

            {/* Theme Input with Trigger Button */}
            <div className="flex gap-2">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика бизнеса..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-3 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-2 rounded-lg border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-500 border-blue-600'}`}
                title="Подобрать ключевые слова через ИИ"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : <Search size={20} />}
              </button>
            </div>

            <button onClick={() => setShowSelected(true)} className="w-full py-1.5 text-xs bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-medium flex items-center justify-center gap-2">
              <List size={14} /> Отобранные слова ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-2 space-y-1 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-3">
                 <Loader2 className="animate-spin text-blue-500" size={32} />
                 <p className="text-sm text-gray-500">ИИ подбирает лучшие запросы и синонимы для вашей тематики...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-10 px-4">
                <p className="text-sm text-gray-400">Введите тематику и нажмите на лупу, чтобы ИИ предложил ключевые слова</p>
                {!currentProjectId && <p className="text-[10px] text-blue-500 mt-4 uppercase font-bold animate-pulse">Проект будет создан автоматически</p>}
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-2 rounded hover:bg-white hover:shadow-sm border border-transparent hover:border-gray-200 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-sm text-gray-700 flex-1">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {/* Preliminary Actions */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-4 bg-white border-t border-gray-200 space-y-2 animate-in slide-in-from-bottom-5">
              <p className="text-[10px] text-gray-400 uppercase font-bold text-center">Выбрано: {selection.size}</p>
              <div className="grid grid-cols-1 gap-2">
                <button onClick={() => moveKeywords('selected')} className="flex items-center justify-center gap-2 py-2 px-3 bg-blue-50 text-blue-700 rounded-lg text-sm font-medium border border-blue-100 hover:bg-blue-100 transition-colors">
                  <ArrowRight size={14} /> В список для поиска
                </button>
                <div className="grid grid-cols-2 gap-2">
                  <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-2 py-2 px-3 bg-red-50 text-red-700 rounded-lg text-sm font-medium border border-red-100 hover:bg-red-100 transition-colors">
                    <MinusSquare size={14} /> В минус
                  </button>
                  <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-2 py-2 px-3 bg-gray-50 text-gray-700 rounded-lg text-sm font-medium border border-gray-100 hover:bg-gray-100 transition-colors">
                    <Trash2 size={14} /> Удалить
                  </button>
                </div>
              </div>
            </div>
          )}

          <div className="p-3 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={18} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-4 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-4 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded-lg text-sm font-semibold transition-all shadow-lg shadow-indigo-200"
                >
                <BrainCircuit size={16} /> Умный отбор
              </button>

              {/* Requested Button: Список для поиска */}
              <button 
                onClick={() => { setShowSelected(true); setSelection(new Set()); }}
                className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg text-sm font-semibold border border-slate-200 transition-all"
              >
                <List size={16} /> Список для поиска
              </button>

              <div className="h-6 w-px bg-gray-200 mx-2" />
              <div className="relative w-64">
                <input 
                  type="text" 
                  placeholder="Поиск по спаршенным словам..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-2 hover:bg-gray-100 rounded-lg text-gray-600 border border-gray-200 flex items-center gap-2 text-sm">
                <Plus size={16} /> Новая группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {!currentProject ? (
              <div className="col-span-full flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={64} className="text-gray-200" />
                <p className="text-lg font-medium">Создайте проект, чтобы начать анализ слов</p>
                <button onClick={() => createProject()} className="px-6 py-2 bg-blue-600 text-white rounded-full font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="col-span-full flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Search size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Спаршенных слов пока нет. Отберите семена слева и запустите анализ.</p>
              </div>
            ) : (
              <>
                <div className="col-span-full flex justify-between items-center mb-3">
                  <h3 className="text-sm font-bold text-gray-500 uppercase tracking-widest">Все запросы ({filteredKeywords('parsed').length})</h3>
                </div>
                {currentProject.groups.map(group => (
                  <div key={group.id} className="bg-white rounded-xl border border-gray-200 shadow-sm flex flex-col h-64">
                    <div className="p-3 border-b flex justify-between items-center bg-gray-50 rounded-t-xl">
                      <span className="text-sm font-bold text-gray-700">{group.name}</span>
                      <span className="text-xs text-gray-400">{currentProject.keywords.filter(k => k.groupId === group.id && k.status === 'parsed').length}</span>
                    </div>
                    <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {currentProject.keywords.filter(k => k.groupId === group.id && k.status === 'parsed').map(k => (
                        <div key={k.id} className="flex items-center p-2 rounded hover:bg-blue-50 transition-colors">
                          <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2" />
                          <span className={`text-xs ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'}`}>{k.text}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}

                {/* Ungrouped */}
                <div className="col-span-full mt-4">
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm min-h-[400px]">
                    <div className="p-3 border-b flex justify-between items-center bg-gray-50 rounded-t-xl">
                      <span className="text-sm font-bold text-gray-700">Основные результаты</span>
                      <span className="text-xs text-gray-400">{filteredKeywords('parsed').filter(k => !k.groupId).length}</span>
                    </div>
                    <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-2">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <div key={k.id} className={`flex items-center p-2 rounded-lg border ${selection.has(k.id) ? 'bg-blue-50 border-blue-200' : 'bg-gray-50 border-gray-100'} hover:border-blue-200 transition-all`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-3"
                          />
                          <span className={`text-sm truncate flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                          {k.aiSuggestedNegative && <BrainCircuit className="text-indigo-400 ml-1" size={14} title="ИИ пометил как негативное" />}
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions for Right Panel */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-4 bg-white border-t border-gray-200 shadow-2xl flex items-center justify-center gap-4 z-40">
                <span className="text-sm font-bold text-gray-500 mr-4">Выбрано слов: {selection.size}</span>
                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-2.5 px-6 bg-red-600 text-white rounded-full text-sm font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-200">
                  <MinusSquare size={18} /> В минус-слова
                </button>
                <div className="relative group">
                  <button className="flex items-center gap-2 py-2.5 px-6 bg-blue-600 text-white rounded-full text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-200">
                    <Layers size={18} /> Перенести в группу <ChevronDown size={14} />
                  </button>
                  <div className="absolute bottom-full mb-2 left-0 w-48 bg-white border border-gray-200 rounded-xl shadow-xl hidden group-hover:block p-2">
                    {currentProject?.groups.map(g => (
                      <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-2 text-sm hover:bg-blue-50 rounded-lg">
                        {g.name}
                      </button>
                    ))}
                    <div className="h-px bg-gray-100 my-1" />
                    <button onClick={createGroup} className="w-full text-left p-2 text-sm text-blue-600 font-bold hover:bg-blue-50 rounded-lg">
                      + Создать новую
                    </button>
                  </div>
                </div>
                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-2.5 px-6 bg-gray-200 text-gray-700 rounded-full text-sm font-bold hover:bg-gray-300 transition-all">
                  <Trash2 size={18} /> Удалить
                </button>
                <button onClick={() => setSelection(new Set())} className="p-2.5 bg-gray-100 hover:bg-gray-200 rounded-full text-gray-500">
                  <X size={18} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Modals */}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-xl font-bold text-gray-800">Мои Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>
            <div className="p-4 max-h-[60vh] overflow-y-auto space-y-3">
              {projects.length === 0 && (
                <div className="text-center py-8">
                  <p className="text-gray-400 text-sm">У вас еще нет созданных проектов</p>
                </div>
              )}
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-500 bg-blue-50 shadow-md' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="font-bold text-gray-800">{p.name}</h3>
                    <p className="text-xs text-gray-400 mt-1">Создан: {new Date(p.createdAt).toLocaleDateString()}</p>
                    <p className="text-xs text-blue-600 font-medium mt-1">{p.keywords.length} ключевых слов</p>
                  </div>

                  {projectToDeleteId === p.id ? (
                    <div className="flex flex-col items-center gap-1 bg-red-50 p-1 rounded-lg border border-red-200 animate-in zoom-in-95" onClick={(e) => e.stopPropagation()}>
                       <p className="text-[10px] text-red-600 font-bold uppercase">Удалить?</p>
                       <div className="flex gap-2">
                          <button onClick={() => deleteProject(p.id)} className="p-1 px-2 bg-red-600 text-white text-[10px] rounded font-bold hover:bg-red-700">Да</button>
                          <button onClick={() => setProjectToDeleteId(null)} className="p-1 px-2 bg-gray-200 text-gray-700 text-[10px] rounded font-bold hover:bg-gray-300">Нет</button>
                       </div>
                    </div>
                  ) : (
                    <button 
                      onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }}
                      className="p-2 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      title="Удалить проект"
                    >
                      <Trash2 size={18} />
                    </button>
                  )}
                </div>
              ))}
            </div>
            <div className="p-6 bg-gray-50">
              <button 
                onClick={() => createProject()}
                className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-blue-200 transition-all"
              >
                <Plus size={20} /> Создать новый проект
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Negative Keywords Modal */}
      {showNegatives && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl w-full max-w-2xl h-[80vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-red-50">
              <div>
                <h2 className="text-xl font-bold text-red-700 flex items-center gap-2">
                  <MinusSquare size={24} /> Минус-слова
                </h2>
                <p className="text-xs text-red-400 mt-1 uppercase tracking-widest font-bold">Удаляйте мусор для чистой рекламы</p>
              </div>
              <button onClick={() => setShowNegatives(false)} className="p-2 hover:bg-red-100 rounded-full transition-colors text-red-700">
                <X size={24} />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 bg-gray-50/50">
               <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                 {currentProject?.keywords.filter(k => k.status === 'negative').map(k => (
                   <div key={k.id} className="flex items-center gap-2 p-2 bg-white border rounded-lg shadow-sm group">
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} />
                     <span className="text-sm text-gray-700 flex-1 truncate">{k.text}</span>
                   </div>
                 ))}
                 {currentProject?.keywords.filter(k => k.status === 'negative').length === 0 && (
                    <div className="col-span-full py-20 text-center text-gray-400">
                      Список минус-слов пока пуст
                    </div>
                 )}
               </div>
            </div>
            {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'negative') && (
              <div className="p-4 bg-white border-t flex justify-center gap-4">
                <button onClick={() => moveKeywords('preliminary')} className="px-6 py-2 bg-blue-50 text-blue-600 rounded-lg font-bold border border-blue-100 hover:bg-blue-100 flex items-center gap-2">
                  <RotateCcw size={16} /> Вернуть в основной список
                </button>
                <button onClick={() => moveKeywords('trash')} className="px-6 py-2 bg-red-50 text-red-600 rounded-lg font-bold border border-red-100 hover:bg-red-100 flex items-center gap-2">
                  <Trash2 size={16} /> Удалить навсегда
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal (Список для поиска) */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] flex flex-col shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-blue-50/30">
              <div className="flex items-center gap-4">
                <List size={28} className="text-blue-600" />
                <div>
                  <h2 className="text-xl font-bold text-blue-900">Список для поиска (Семена)</h2>
                  <p className="text-xs text-blue-500 uppercase tracking-wider font-bold">ИИ соберет все возможные запросы по этим словам</p>
                </div>
              </div>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-2 hover:bg-blue-100 rounded-full transition-colors text-blue-800">
                <X size={24} />
              </button>
            </div>

            <div className="p-4 bg-gray-50 border-b flex justify-between items-center">
              <button 
                onClick={toggleSelectAllSelected}
                className="text-sm font-bold text-blue-600 hover:underline flex items-center gap-2"
              >
                <CheckSquare size={16} />
                {currentProject?.keywords.filter(k => k.status === 'selected').every(k => selection.has(k.id)) 
                  ? "Снять выделение" 
                  : "Выбрать все"}
              </button>
              <span className="text-xs text-gray-400 font-bold uppercase">Выбрано: {currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length}</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 bg-white">
               <div className="flex flex-col gap-2">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-400 bg-blue-50/30' : 'border-gray-50 hover:border-blue-200'}`}>
                     <input 
                      type="checkbox" 
                      checked={selection.has(k.id)} 
                      onChange={() => toggleSelect(k.id)} 
                      className="h-5 w-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                     />
                     <span className="text-base font-semibold text-gray-800">{k.text}</span>
                   </label>
                 ))}
                 {currentProject?.keywords.filter(k => k.status === 'selected').length === 0 && (
                    <div className="py-20 text-center text-gray-400 flex flex-col items-center gap-4">
                      <List size={64} className="text-gray-100" />
                      <p className="text-lg">Список для поиска пуст. <br/> Добавьте слова из предварительного отбора.</p>
                    </div>
                 )}
               </div>
            </div>

            <div className="p-6 bg-gray-50 border-t space-y-4 shadow-inner">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-5 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-2xl font-black text-xl flex items-center justify-center gap-4 shadow-xl shadow-green-100 transition-all uppercase tracking-widest"
                >
                  {loading ? <Loader2 className="animate-spin" size={28} /> : <Play size={28} fill="currentColor" />}
                  Начать сбор запросов
               </button>

               {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'selected') && (
                  <div className="flex gap-3 animate-in slide-in-from-bottom-2">
                    <button onClick={() => moveKeywords('preliminary')} className="flex-1 py-3 px-4 bg-white text-slate-700 rounded-xl text-sm font-bold border border-slate-200 hover:bg-slate-50 flex items-center justify-center gap-2 shadow-sm">
                      <RotateCcw size={16} /> В основной список
                    </button>
                    <button onClick={() => moveKeywords('trash')} className="flex-1 py-3 px-4 bg-red-50 text-red-600 rounded-xl text-sm font-bold border border-red-100 hover:bg-red-100 flex items-center justify-center gap-2 shadow-sm">
                      <Trash2 size={16} /> Удалить
                    </button>
                  </div>
               )}
            </div>
          </div>
        </div>
      )}

      {/* Trash Modal */}
      {showTrash && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl w-full max-w-md h-[60vh] flex flex-col shadow-2xl">
            <div className="p-6 border-b flex justify-between items-center bg-gray-100">
              <h2 className="text-xl font-bold text-gray-700 flex items-center gap-2">
                <Trash2 size={24} /> Корзина
              </h2>
              <button onClick={() => setShowTrash(false)}><X size={24} /></button>
            </div>
            <div className="p-4 bg-gray-50">
              <input 
                type="text" 
                placeholder="Поиск по корзине..."
                className="w-full px-4 py-2 border rounded-lg shadow-inner outline-none"
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-2">
              {filteredKeywords('trash').map(k => (
                <div key={k.id} className="flex items-center gap-2 p-3 bg-white border rounded-lg">
                  <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} />
                  <span className="text-sm text-gray-500 line-through">{k.text}</span>
                </div>
              ))}
            </div>
            {selection.size > 0 && (
               <div className="p-4 border-t flex gap-2">
                 <button onClick={() => moveKeywords('preliminary')} className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold">Восстановить</button>
               </div>
            )}
          </div>
        </div>
      )}

      {/* Advanced Analysis Breakdown Modal */}
      {showAnalysis && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[60] flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl w-full max-w-6xl h-[90vh] flex flex-col shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
             <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
               <div className="flex items-center gap-4">
                 <Search size={32} className="text-blue-400" />
                 <div>
                   <h2 className="text-2xl font-black">Глубокий Анализ Слов</h2>
                   <p className="text-slate-400 text-sm">Алфавитный разбор семантического ядра</p>
                 </div>
               </div>
               <button onClick={() => setShowAnalysis(false)} className="p-3 hover:bg-slate-800 rounded-full transition-colors">
                 <X size={32} />
               </button>
             </div>

             <div className="flex-1 overflow-hidden flex">
               {/* Left: Alphabet/Words list */}
               <div className="w-1/3 border-r border-slate-100 flex flex-col overflow-hidden">
                 <div className="p-4 bg-slate-50 border-b">
                    <div className="relative">
                      <input type="text" placeholder="Поиск по словам..." className="w-full pl-10 pr-4 py-2 bg-white border rounded-xl shadow-inner outline-none focus:ring-2 focus:ring-blue-500" />
                      <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
                    </div>
                 </div>
                 <div className="flex-1 overflow-y-auto p-4 space-y-2">
                    {/* Mock breakdown: unique words extracted from all parsed phrases */}
                    {(Array.from(new Set((currentProject?.keywords.filter(k => k.status === 'parsed') || []).flatMap(k => k.text.toLowerCase().split(' ')))) as string[])
                      .sort((a, b) => a.localeCompare(b))
                      .map(word => {
                        const occurrences = currentProject?.keywords.filter(k => k.status === 'parsed' && k.text.toLowerCase().includes(word)).length || 0;
                        if (word.length < 3) return null;
                        return (
                          <div key={word} className="group p-3 rounded-xl border border-slate-50 hover:bg-blue-50 hover:border-blue-200 transition-all cursor-pointer flex justify-between items-center">
                             <div className="flex items-center gap-3">
                               <input type="checkbox" className="h-5 w-5 rounded-md" />
                               <span className="font-bold text-slate-700 capitalize">{word}</span>
                             </div>
                             <span className="px-2 py-1 bg-slate-200 group-hover:bg-blue-200 text-[10px] rounded font-bold text-slate-500 group-hover:text-blue-600">{occurrences}</span>
                          </div>
                        );
                      })}
                 </div>
               </div>

               {/* Right: Specific Phrases Container */}
               <div className="flex-1 bg-slate-50/50 p-8 overflow-y-auto">
                 <div className="max-w-3xl mx-auto space-y-8 text-center py-20">
                   <div className="w-24 h-24 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-6">
                     <Search className="text-blue-600" size={48} />
                   </div>
                   <h3 className="text-3xl font-black text-slate-800">Выберите слово слева</h3>
                   <p className="text-slate-500 text-lg">Вы увидите все фразы, в которых встречается это слово. Вы сможете массово удалять их или отправлять в минус-слова.</p>
                 </div>
               </div>
             </div>

             <div className="p-6 bg-slate-900 border-t border-slate-800 flex justify-between items-center text-white">
                <p className="text-slate-400 text-sm">Всего уникальных основ: 124</p>
                <div className="flex gap-4">
                  <button className="px-8 py-3 bg-red-600 rounded-xl font-black hover:bg-red-500 shadow-xl shadow-red-900/20 transition-all">В минус</button>
                  <button className="px-8 py-3 bg-slate-700 rounded-xl font-black hover:bg-slate-600 transition-all">Удалить</button>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  // Sync theme input with current project whenever it changes
  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set()); // Clear selection when switching projects
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;

    // Auto-create project if none exists or is selected
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      const newKeywords: Keyword[] = suggestions.map(text => ({
        id: Math.random().toString(36).substr(2, 9),
        text,
        status: 'preliminary'
      }));

      // Update directly to ensure the logic works even if activeProjectId was just set
      setProjects(prev => prev.map(p => p.id === activeProjectId ? {
        ...p,
        theme: input,
        keywords: [
          ...p.keywords.filter(k => k.status !== 'preliminary'),
          ...newKeywords
        ]
      } : p));
    } catch (e) {
      console.error(e);
      alert("Ошибка ИИ. Проверьте соединение или API ключ.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      const newKeywords: Keyword[] = expanded.map(text => ({
        id: Math.random().toString(36).substr(2, 9),
        text,
        status: 'parsed'
      }));
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...newKeywords]
      }));
      setShowSelected(false);
      setSelection(new Set());
    } catch (e) {
      console.error(e);
      alert("Ошибка при сборе запросов через ИИ.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);

    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) {
      allIds.forEach(id => currentSelection.delete(id));
    } else {
      allIds.forEach(id => currentSelection.add(id));
    }
    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);

      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') {
        items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      } else if (sortOrder === 'desc') {
        items = [...items].sort((a, b) => b.text.localeCompare(a.text));
      }
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              ИИ анализирует...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-4 border-b border-gray-100 space-y-4">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-xs tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-xs text-red-500 hover:underline flex items-center gap-1">
                <MinusSquare size={12} /> Минус-слова
              </button>
            </div>

            {/* Theme Input with Trigger Button */}
            <div className="flex gap-2">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика бизнеса..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-3 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-2 rounded-lg border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-500 border-blue-600'}`}
                title="Подобрать ключевые слова через ИИ"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : <Search size={20} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1.5 text-xs bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-medium flex items-center justify-center gap-2">
