import { GoogleGenAI, Type } from "@google/genai";

// Initialize the GoogleGenAI with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Utility for retrying API calls with exponential backoff
 */
async function callWithRetry<T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries > 0 && (error?.status === 500 || error?.status === 503 || error?.message?.includes('xhr error') || error?.message?.includes('ProxyUnaryCall'))) {
      console.warn(`API call failed, retrying in ${delay}ms...`, error);
      await new Promise(resolve => setTimeout(resolve, delay));
      return callWithRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const fetchSynonymsAndSuggestions = async (theme: string) => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ты - эксперт по контекстной рекламе (Google Ads, Яндекс.Директ). 
      Сгенерируй максимально полный список базовых ключевых слов, синонимов и высокочастотных запросов для тематики бизнеса: "${theme}".

      Включи в список:
      1. Прямые названия услуг/товаров.
      2. Синонимы и профессиональный сленг.
      3. Слова с частыми ошибками и опечатками.
      4. Ассоциативные слова.

      Верни ТОЛЬКО слова через запятую, без лишнего текста и нумерации. На русском языке.`,
      config: {
        temperature: 0.7,
      },
    });

    const text = response.text || "";
    return text.split(/[,;\n]/).map(s => s.trim()).filter(s => s.length > 0);
  });
};

export const expandKeywords = async (baseKeywords: string[], theme: string) => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ты - профессиональный SEO и SEM эксперт. Собери АБСОЛЮТНО ВСЕ возможные поисковые запросы на основе семян: ${baseKeywords.join(', ')}.
      Тематика бизнеса: "${theme}". 

      Требования:
      1. Собери все запросы, включая нулевые по частотности.
      2. Придумай все комбинации (цена, купить, заказать, под ключ, гео, сленг).
      3. НИЧЕГО НЕ ПРОПУСКАЙ. Нужен объем.

      Верни результат в формате JSON массива строк. Только массив.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      },
    });

    try {
      return JSON.parse(response.text || "[]") as string[];
    } catch (e) {
      console.error("Failed to parse expanded keywords", e);
      return [];
    }
  });
};

