      ${keywords.map((k, i) => `${i}: ${k}`).join('\n')}

      Определи индексы слов, которые на 100% являются мусором для рекламы (инфо-запросы, поиск работы и т.д.).
      Верни JSON массив индексов (0-based).`,
      config: {
        // Correctly setting thinkingBudget alongside maxOutputTokens as per guidelines
        maxOutputTokens: 10000,
        thinkingConfig: { thinkingBudget: 8000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.INTEGER }
        },
      },
    });

    try {
      return JSON.parse(response.text || "[]") as number[];
    } catch (e) {
      return [];
    }
  });
};

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the GoogleGenAI with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Utility for retrying API calls with basic backoff for stability
 */
async function callWithRetry<T>(fn: () => Promise<T>, retries = 2, delay = 500): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    if (retries > 0 && (error?.status === 500 || error?.status === 503 || error?.message?.includes('xhr error') || error?.message?.includes('ProxyUnaryCall'))) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callWithRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

export const fetchSynonymsAndSuggestions = async (theme: string) => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ты - эксперт по контекстной рекламе. 
      Сгенерируй список базовых ключевых слов, синонимов и запросов для тематики: "${theme}".
      Верни ТОЛЬКО слова через запятую.`,
      config: {
        temperature: 0.7,
      },
    });

    const text = response.text || "";
    return text.split(/[,;\n]/).map(s => s.trim()).filter(s => s.length > 0);
  });
};

export const expandKeywords = async (baseKeywords: string[], theme: string) => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Собери все возможные поисковые запросы на основе семян: ${baseKeywords.join(', ')}.
      Тематика: "${theme}". Включай комбинации (цена, купить, заказать, под ключ).
      Верни JSON массив строк.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      },
    });

    try {
      return JSON.parse(response.text || "[]") as string[];
    } catch (e) {
      return [];
    }
  });
};

export const smartFilterKeywords = async (keywords: string[], theme: string) => {
