import { GoogleGenAI, Type } from "@google/genai";

// Initialize the GoogleGenAI with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Utility for retrying API calls with basic backoff for stability
 */
async function callWithRetry<T>(fn: () => Promise<T>, retries = 2, delay = 1000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    // Specific check for Quota Exceeded (429)
    if (error?.status === 429 || error?.message?.includes('429') || error?.message?.includes('quota')) {
       throw new Error("QUOTA_EXCEEDED");
    }

    if (retries > 0 && (error?.status === 500 || error?.status === 503 || error?.message?.includes('xhr error') || error?.message?.includes('ProxyUnaryCall'))) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return callWithRetry(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

const handleApiError = (e: any) => {
  if (e.message === "QUOTA_EXCEEDED") {
    alert("Превышена квота запросов API Gemini. Пожалуйста, подождите 1-2 минуты или переключитесь на платный тариф (billing).");
  } else {
    alert("Не удалось вызвать API Gemini. Попробуйте еще раз позже.");
  }
  console.error(e);
};

export const fetchSynonymsAndSuggestions = async (theme: string) => {
  try {
    return await callWithRetry(async () => {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Ты - эксперт по контекстной рекламе. 
        Сгенерируй список базовых ключевых слов, синонимов и запросов для тематики: "${theme}".
        Верни ТОЛЬКО слова через запятую.`,
        config: {
          temperature: 0.7,
        },
      });

      const text = response.text || "";
      return text.split(/[,;\n]/).map(s => s.trim()).filter(s => s.length > 0);
    });
  } catch (e) {
    handleApiError(e);
    return [];
  }
};

export const expandKeywords = async (baseKeywords: string[], theme: string) => {
  try {
    return await callWithRetry(async () => {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Собери все возможные поисковые запросы на основе семян: ${baseKeywords.join(', ')}.
        Тематика: "${theme}". Включай комбинации (цена, купить, заказать, под ключ).
        Верни JSON массив строк.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
      });

      return JSON.parse(response.text || "[]") as string[];
    });
  } catch (e) {
    handleApiError(e);
    return [];
  }
};

export const smartFilterKeywords = async (keywords: string[], theme: string) => {
  try {
    return await callWithRetry(async () => {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Проанализируй список слов для ниши "${theme}":
        ${keywords.map((k, i) => `${i}: ${k}`).join('\n')}
        Найди мусорные запросы (инфо, работа, бесплатно). Верни JSON массив их индексов.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.INTEGER }
          },
        },
      });

      return JSON.parse(response.text || "[]") as number[];
    });
  } catch (e) {
    handleApiError(e);
    return [];
  }
};

