  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    // Use a Set for fast exact-match lookup (ignoring leading/trailing spaces and casing)
    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);
    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) allIds.forEach(id => currentSelection.delete(id));
    else allIds.forEach(id => currentSelection.add(id));

    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              Обработка...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-4 border-b border-gray-100 space-y-4">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-xs tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-xs text-red-500 hover:underline flex items-center gap-1">
                <MinusSquare size={12} /> Минус-слова
              </button>
            </div>

            <div className="flex gap-2">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика бизнеса..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-3 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-2 rounded-lg border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-500 border-blue-600'}`}
                title="Подобрать ключевые слова через ИИ"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : <Search size={20} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1.5 text-xs bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-medium flex items-center justify-center gap-2">
              <List size={14} /> Отобранные слова ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-2 space-y-1 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-3">
                 <Loader2 className="animate-spin text-blue-500" size={32} />
                 <p className="text-sm text-gray-500">ИИ подбирает лучшие запросы и синонимы...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-10 px-4">
                <p className="text-sm text-gray-400">Введите тематику и нажмите на лупу</p>
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-2 rounded hover:bg-white hover:shadow-sm border border-transparent hover:border-gray-200 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-sm text-gray-700 flex-1">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-4 bg-white border-t border-gray-200 space-y-2 animate-in slide-in-from-bottom-5">
              <p className="text-[10px] text-gray-400 uppercase font-black text-center">Выбрано: {selection.size}</p>
              <div className="grid grid-cols-1 gap-2">
                <button onClick={() => moveKeywords('selected')} className="flex items-center justify-center gap-2 py-2 px-3 bg-blue-50 text-blue-700 rounded-lg text-sm font-bold border border-blue-100 hover:bg-blue-100 transition-colors">
                  <ArrowRight size={14} /> В список для поиска
                </button>
                <div className="grid grid-cols-2 gap-2">
                  <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-2 py-2 px-3 bg-red-50 text-red-700 rounded-lg text-sm font-bold border border-red-100 hover:bg-red-100 transition-colors">
                    <MinusSquare size={14} /> В минус
                  </button>
                  <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-2 py-2 px-3 bg-gray-50 text-gray-700 rounded-lg text-sm font-bold border border-gray-100 hover:bg-gray-100 transition-colors">
                    <Trash2 size={14} /> Удалить
                  </button>
                </div>
              </div>
            </div>
          )}

          <div className="p-3 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={18} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-4 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-4 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded-lg text-sm font-semibold transition-all shadow-lg shadow-indigo-200"
                >
                <BrainCircuit size={16} /> Умный отбор
              </button>

              <button 
                onClick={() => setShowBulkAdd(true)}
                disabled={!currentProject}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-300 text-white rounded-lg text-sm font-semibold transition-all shadow-lg shadow-blue-100"
              >
                <Upload size={16} /> Добавить список
              </button>

              <div className="h-6 w-px bg-gray-200 mx-2" />

              <div className="flex items-center gap-2">
                <div className="relative w-64">
                  <input 
                    type="text" 
                    placeholder="Поиск по словам..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                  <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-2 hover:bg-gray-100 rounded-lg text-gray-600 border border-gray-200 flex items-center gap-2 text-sm font-medium">
                <Plus size={16} /> Новая группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-6">
            {!currentProject ? (
              <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={64} className="text-gray-200" />
                <p className="text-lg font-medium">Создайте проект, чтобы начать</p>
                <button onClick={() => createProject()} className="px-6 py-2 bg-blue-600 text-white rounded-full font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Search size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Спаршенных слов пока нет. Добавьте список или запустите ИИ сбор.</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center">
                  <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest">Все запросы ({filteredKeywords('parsed').length})</h3>
                  <div className="flex items-center gap-2">
                    <button onClick={() => setSortOrder('asc')} className={`p-1 rounded ${sortOrder === 'asc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortAsc size={14}/></button>
                    <button onClick={() => setSortOrder('desc')} className={`p-1 rounded ${sortOrder === 'desc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortDesc size={14}/></button>
                  </div>
                </div>

                {/* Groups Display */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    if (groupKeywords.length === 0 && searchQuery) return null;
                    return (
                      <div key={group.id} className="bg-white rounded-xl border border-gray-200 shadow-sm flex flex-col h-72">
                        <div className="p-3 border-b flex justify-between items-center bg-blue-50/50 rounded-t-xl">
                          <span className="text-sm font-bold text-slate-700 truncate">{group.name}</span>
                          <span className="text-[10px] bg-white px-2 py-1 rounded-full border border-blue-100 font-bold text-blue-600 shadow-sm">{groupKeywords.length}</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-3 space-y-1">
                          {groupKeywords.map(k => (
                            <label key={k.id} className={`flex items-center p-2 rounded-lg transition-colors cursor-pointer ${selection.has(k.id) ? 'bg-blue-50' : 'hover:bg-gray-50'}`}>
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-3 h-4 w-4 text-blue-600 rounded" />
                              <span className={`text-xs ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'} font-medium`}>{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Main Results (Ungrouped) */}
                <div className="w-full">
                  <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
                    <div className="p-4 border-b flex justify-between items-center bg-gray-50/80">
                      <div className="flex items-center gap-2">
                        <Layers size={18} className="text-gray-400" />
                        <span className="text-sm font-black text-gray-700 uppercase tracking-tight">Основные результаты</span>
                      </div>
                      <span className="text-xs font-bold text-gray-400 px-3 py-1 bg-white rounded-full border border-gray-100">{filteredKeywords('parsed').filter(k => !k.groupId).length} слов</span>
                    </div>

                    <div className="p-4 flex flex-col gap-2">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <label key={k.id} className={`flex items-center p-3 rounded-xl border-2 transition-all cursor-pointer ${selection.has(k.id) ? 'bg-blue-50 border-blue-200 shadow-sm' : 'bg-white border-gray-50 hover:border-gray-200 hover:shadow-sm'}`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-4 h-5 w-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className={`text-sm font-semibold flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-6 bg-white/95 backdrop-blur-md border-t border-gray-200 shadow-2xl flex items-center justify-center gap-6 z-40 animate-in slide-in-from-bottom-10">
                <div className="flex flex-col text-center">
                  <span className="text-[10px] text-gray-400 uppercase font-black">Выбрано</span>
                  <span className="text-xl font-black text-blue-600 leading-none">{selection.size}</span>
                </div>

                <div className="h-10 w-px bg-gray-200 mx-2" />

                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-3 py-3 px-8 bg-red-600 text-white rounded-2xl text-sm font-black hover:bg-red-700 transition-all shadow-xl shadow-red-200 uppercase tracking-widest">
                  <MinusSquare size={20} /> В минус-слова
                </button>

                <div className="relative group">
                  <button className="flex items-center gap-3 py-3 px-8 bg-blue-600 text-white rounded-2xl text-sm font-black hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 uppercase tracking-widest">
                    <Layers size={20} /> Перенести в группу <ChevronDown size={16} />
                  </button>
                  <div className="absolute bottom-full mb-3 left-0 w-64 bg-white border border-gray-200 rounded-2xl shadow-2xl hidden group-hover:block p-3 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-60 overflow-y-auto space-y-1 mb-2">
                      {currentProject?.groups.map(g => (
                        <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-2.5 text-sm hover:bg-blue-50 rounded-xl font-bold text-gray-600 transition-colors">
                          {g.name}
                        </button>
                      ))}
                    </div>
                    <div className="h-px bg-gray-100 my-2" />
                    <button onClick={createGroup} className="w-full text-center p-2.5 text-xs text-blue-600 font-black hover:bg-blue-50 rounded-xl uppercase border border-dashed border-blue-200">
                      + Создать новую группу
                    </button>
                  </div>
                </div>

                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-3 py-3 px-8 bg-gray-100 text-gray-700 rounded-2xl text-sm font-black hover:bg-gray-200 transition-all uppercase tracking-widest border border-gray-200">
                  <Trash2 size={20} /> Удалить
                </button>

                <button onClick={() => setSelection(new Set())} className="p-3 bg-gray-50 hover:bg-red-50 hover:text-red-500 rounded-2xl text-gray-400 transition-all border border-gray-100">
                  <X size={24} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl w-full max-w-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-6 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-blue-600 text-white rounded-2xl"><Upload size={24} /></div>
                    <div>
                       <h2 className="text-xl font-bold text-blue-900">Массовая загрузка</h2>
                       <p className="text-sm text-blue-400">Вставьте список или загрузите файл (.txt)</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-2 hover:bg-blue-100 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-6 space-y-6">
                 <div className="flex gap-4">
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="flex-1 py-3 px-4 bg-white border-2 border-dashed border-gray-300 rounded-2xl flex flex-col items-center justify-center gap-2 hover:border-blue-400 hover:bg-blue-50 transition-all"
                    >
                       <FileText size={32} className="text-gray-400" />
                       <span className="text-sm font-bold text-gray-600">Выбрать файл</span>
                       <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                    </button>
                 </div>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Введите каждое слово с новой строки..."
                     className="w-full h-64 p-4 border-2 border-gray-100 rounded-2xl focus:border-blue-500 outline-none font-mono text-sm resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-4 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-blue-200 uppercase tracking-widest"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-xl font-bold text-gray-800">Мои Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>
            <div className="p-4 max-h-[60vh] overflow-y-auto space-y-3">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-500 bg-blue-50 shadow-md' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="font-bold text-gray-800">{p.name}</h3>
                    <p className="text-xs text-blue-600 font-medium mt-1">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                </div>
              ))}
            </div>
            <div className="p-6 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all"><Plus size={20} /> Новый проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] flex flex-col shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-blue-50/30">
              <h2 className="text-xl font-bold">Список для поиска (Семена)</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-2 hover:bg-blue-100 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 bg-white">
               <div className="flex flex-col gap-2">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-400 bg-blue-50/30' : 'border-gray-50 hover:border-blue-200'}`}>
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-5 w-5 text-blue-600 rounded" />
                     <span className="text-base font-semibold text-gray-800">{k.text}</span>
                   </label>
                 ))}
               </div>
            </div>

            <div className="p-6 bg-gray-50 border-t space-y-4">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-5 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-2xl font-black text-xl flex items-center justify-center gap-4 transition-all uppercase tracking-widest"
                >
                  {loading ? <Loader2 className="animate-spin" size={28} /> : <Play size={28} fill="currentColor" />}
                  Начать сбор запросов
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList, Info, Activity, Zap
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);
  const [showApiInfo, setShowApiInfo] = useState(false);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    // Strict exact-match lookup (ignoring leading/trailing spaces and casing for consistency)
    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      // Only skip if it's EXACTLY the same phrase. 
      // Swapped words or different inflections will result in different strings and won't be in the Set.
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);
    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) allIds.forEach(id => currentSelection.delete(id));
    else allIds.forEach(id => currentSelection.add(id));

    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setShowProjectManager(true)}
              className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
            >
              <FolderOpen size={16} />
              {currentProject ? currentProject.name : 'Выбрать проект'}
            </button>

            {/* API Status Info */}
            <div className="relative">
               <button 
                onClick={() => setShowApiInfo(!showApiInfo)}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${loading ? 'bg-amber-900/40 text-amber-400 animate-pulse' : 'bg-green-900/40 text-green-400 hover:bg-green-900/60'}`}
               >
                 <Activity size={14} />
                 Статус: {loading ? 'Обработка' : 'Готов'}
                 <ChevronDown size={12} className={`transition-transform ${showApiInfo ? 'rotate-180' : ''}`} />
               </button>

               {showApiInfo && (
                 <div className="absolute top-full mt-2 left-0 w-72 bg-white rounded-xl shadow-2xl border border-gray-100 p-4 text-slate-800 z-[100] animate-in slide-in-from-top-2">
                   <h3 className="text-sm font-black uppercase text-slate-400 mb-3 flex items-center gap-2">
                     <Zap size={14} className="text-amber-500" /> Лимиты и система
                   </h3>
                   <div className="space-y-3">
                     <div className="flex justify-between items-center text-xs">
                       <span className="text-slate-500">Модель:</span>
                       <span className="font-bold">Gemini 3 Flash</span>
                     </div>
                     <div className="flex justify-between items-center text-xs">
                       <span className="text-slate-500">Запросы/мин (RPM):</span>
                       <span className="font-bold text-blue-600">~15 (Free)</span>
                     </div>
                     <div className="flex justify-between items-center text-xs">
                       <span className="text-slate-500">Токенов/мин (TPM):</span>
                       <span className="font-bold text-blue-600">1,000,000</span>
                     </div>
                     <div className="h-px bg-slate-100 my-2" />
                     <div className="flex items-start gap-2 bg-blue-50 p-2 rounded-lg">
                       <Info size={14} className="text-blue-500 shrink-0 mt-0.5" />
                       <p className="text-[10px] text-blue-700 leading-relaxed">
                         Если возникла ошибка <b>429 (Quota)</b>, просто подождите 60 секунд. Бесплатный тариф имеет ограничение на количество запросов в минуту.
                       </p>
                     </div>
                     <div className="flex items-start gap-2 bg-gray-50 p-2 rounded-lg border border-gray-100">
                       <Sparkles size={14} className="text-slate-400 shrink-0 mt-0.5" />
                       <p className="text-[10px] text-slate-600 leading-relaxed">
                         <b>Совет:</b> Не запускайте "Умный отбор" и "Сбор запросов" одновременно для экономии квот.
                       </p>
                     </div>
                   </div>
                 </div>
               )}
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-4 border-b border-gray-100 space-y-4">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-xs tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-xs text-red-500 hover:underline flex items-center gap-1">
                <MinusSquare size={12} /> Минус-слова
              </button>
            </div>

            <div className="flex gap-2">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика бизнеса..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-3 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-2 rounded-lg border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-500 border-blue-600'}`}
                title="Подобрать ключевые слова через ИИ"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : <Search size={20} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1.5 text-xs bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-medium flex items-center justify-center gap-2">
              <List size={14} /> Отобранные слова ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-2 space-y-1 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-3">
                 <Loader2 className="animate-spin text-blue-500" size={32} />
                 <p className="text-sm text-gray-500">ИИ подбирает лучшие запросы и синонимы...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-10 px-4">
                <p className="text-sm text-gray-400">Введите тематику и нажмите на лупу</p>
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-2 rounded hover:bg-white hover:shadow-sm border border-transparent hover:border-gray-200 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-sm text-gray-700 flex-1">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-4 bg-white border-t border-gray-200 space-y-2 animate-in slide-in-from-bottom-5">
              <p className="text-[10px] text-gray-400 uppercase font-black text-center">Выбрано: {selection.size}</p>
              <div className="grid grid-cols-1 gap-2">
                <button onClick={() => moveKeywords('selected')} className="flex items-center justify-center gap-2 py-2 px-3 bg-blue-50 text-blue-700 rounded-lg text-sm font-bold border border-blue-100 hover:bg-blue-100 transition-colors">
                  <ArrowRight size={14} /> В список для поиска
                </button>
                <div className="grid grid-cols-2 gap-2">
                  <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-2 py-2 px-3 bg-red-50 text-red-700 rounded-lg text-sm font-bold border border-red-100 hover:bg-red-100 transition-colors">
                    <MinusSquare size={14} /> В минус
                  </button>
                  <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-2 py-2 px-3 bg-gray-50 text-gray-700 rounded-lg text-sm font-bold border border-gray-100 hover:bg-gray-100 transition-colors">
                    <Trash2 size={14} /> Удалить
                  </button>
                </div>
              </div>
            </div>
          )}

          <div className="p-3 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={18} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-4 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-4 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded-lg text-sm font-semibold transition-all shadow-lg shadow-indigo-200"
                >
                <BrainCircuit size={16} /> Умный отбор
              </button>

              <button 
                onClick={() => setShowBulkAdd(true)}
                disabled={!currentProject}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-300 text-white rounded-lg text-sm font-semibold transition-all shadow-lg shadow-blue-100"
              >
                <Upload size={16} /> Добавить список
              </button>

              <div className="h-6 w-px bg-gray-200 mx-2" />

              <div className="flex items-center gap-2">
                <div className="relative w-64">
                  <input 
                    type="text" 
                    placeholder="Поиск по словам..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                  <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-2 hover:bg-gray-100 rounded-lg text-gray-600 border border-gray-200 flex items-center gap-2 text-sm font-medium">
                <Plus size={16} /> Новая группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-6">
            {!currentProject ? (
              <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={64} className="text-gray-200" />
                <p className="text-lg font-medium">Создайте проект, чтобы начать</p>
                <button onClick={() => createProject()} className="px-6 py-2 bg-blue-600 text-white rounded-full font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Search size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Спаршенных слов пока нет. Добавьте список или запустите ИИ сбор.</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center">
                  <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest">Все запросы ({filteredKeywords('parsed').length})</h3>
                  <div className="flex items-center gap-2">
                    <button onClick={() => setSortOrder('asc')} className={`p-1 rounded ${sortOrder === 'asc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortAsc size={14}/></button>
                    <button onClick={() => setSortOrder('desc')} className={`p-1 rounded ${sortOrder === 'desc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortDesc size={14}/></button>
                  </div>
                </div>

                {/* Groups Display */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    if (groupKeywords.length === 0 && searchQuery) return null;
                    return (
                      <div key={group.id} className="bg-white rounded-xl border border-gray-200 shadow-sm flex flex-col h-72">
                        <div className="p-3 border-b flex justify-between items-center bg-blue-50/50 rounded-t-xl">
                          <span className="text-sm font-bold text-slate-700 truncate">{group.name}</span>
                          <span className="text-[10px] bg-white px-2 py-1 rounded-full border border-blue-100 font-bold text-blue-600 shadow-sm">{groupKeywords.length}</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-3 space-y-1">
                          {groupKeywords.map(k => (
                            <label key={k.id} className={`flex items-center p-2 rounded-lg transition-colors cursor-pointer ${selection.has(k.id) ? 'bg-blue-50' : 'hover:bg-gray-50'}`}>
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-3 h-4 w-4 text-blue-600 rounded" />
                              <span className={`text-xs ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'} font-medium`}>{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Main Results (Ungrouped) */}
                <div className="w-full">
                  <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
                    <div className="p-4 border-b flex justify-between items-center bg-gray-50/80">
                      <div className="flex items-center gap-2">
                        <Layers size={18} className="text-gray-400" />
                        <span className="text-sm font-black text-gray-700 uppercase tracking-tight">Основные результаты</span>
                      </div>
                      <span className="text-xs font-bold text-gray-400 px-3 py-1 bg-white rounded-full border border-gray-100">{filteredKeywords('parsed').filter(k => !k.groupId).length} слов</span>
                    </div>

                    <div className="p-4 flex flex-col gap-2">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <label key={k.id} className={`flex items-center p-3 rounded-xl border-2 transition-all cursor-pointer ${selection.has(k.id) ? 'bg-blue-50 border-blue-200 shadow-sm' : 'bg-white border-gray-50 hover:border-gray-200 hover:shadow-sm'}`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-4 h-5 w-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className={`text-sm font-semibold flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-6 bg-white/95 backdrop-blur-md border-t border-gray-200 shadow-2xl flex items-center justify-center gap-6 z-40 animate-in slide-in-from-bottom-10">
                <div className="flex flex-col text-center">
                  <span className="text-[10px] text-gray-400 uppercase font-black">Выбрано</span>
                  <span className="text-xl font-black text-blue-600 leading-none">{selection.size}</span>
                </div>

                <div className="h-10 w-px bg-gray-200 mx-2" />

                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-3 py-3 px-8 bg-red-600 text-white rounded-2xl text-sm font-black hover:bg-red-700 transition-all shadow-xl shadow-red-200 uppercase tracking-widest">
                  <MinusSquare size={20} /> В минус-слова
                </button>

                <div className="relative group">
                  <button className="flex items-center gap-3 py-3 px-8 bg-blue-600 text-white rounded-2xl text-sm font-black hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 uppercase tracking-widest">
                    <Layers size={20} /> Перенести в группу <ChevronDown size={16} />
                  </button>
                  <div className="absolute bottom-full mb-3 left-0 w-64 bg-white border border-gray-200 rounded-2xl shadow-2xl hidden group-hover:block p-3 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-60 overflow-y-auto space-y-1 mb-2">
                      {currentProject?.groups.map(g => (
                        <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-2.5 text-sm hover:bg-blue-50 rounded-xl font-bold text-gray-600 transition-colors">
                          {g.name}
                        </button>
                      ))}
                    </div>
                    <div className="h-px bg-gray-100 my-2" />
                    <button onClick={createGroup} className="w-full text-center p-2.5 text-xs text-blue-600 font-black hover:bg-blue-50 rounded-xl uppercase border border-dashed border-blue-200">
                      + Создать новую группу
                    </button>
                  </div>
                </div>

                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-3 py-3 px-8 bg-gray-100 text-gray-700 rounded-2xl text-sm font-black hover:bg-gray-200 transition-all uppercase tracking-widest border border-gray-200">
                  <Trash2 size={20} /> Удалить
                </button>

                <button onClick={() => setSelection(new Set())} className="p-3 bg-gray-50 hover:bg-red-50 hover:text-red-500 rounded-2xl text-gray-400 transition-all border border-gray-100">
                  <X size={24} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl w-full max-w-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-6 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-blue-600 text-white rounded-2xl"><Upload size={24} /></div>
                    <div>
                       <h2 className="text-xl font-bold text-blue-900">Массовая загрузка</h2>
                       <p className="text-sm text-blue-400">Вставьте список или загрузите файл (.txt)</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-2 hover:bg-blue-100 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-6 space-y-6">
                 <div className="flex gap-4">
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="flex-1 py-3 px-4 bg-white border-2 border-dashed border-gray-300 rounded-2xl flex flex-col items-center justify-center gap-2 hover:border-blue-400 hover:bg-blue-50 transition-all"
                    >
                       <FileText size={32} className="text-gray-400" />
                       <span className="text-sm font-bold text-gray-600">Выбрать файл</span>
                       <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                    </button>
                 </div>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Введите каждое слово с новой строки..."
                     className="w-full h-64 p-4 border-2 border-gray-100 rounded-2xl focus:border-blue-500 outline-none font-mono text-sm resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-4 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-blue-200 uppercase tracking-widest"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-xl font-bold text-gray-800">Мои Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>
            <div className="p-4 max-h-[60vh] overflow-y-auto space-y-3">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-500 bg-blue-50 shadow-md' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="font-bold text-gray-800">{p.name}</h3>
                    <p className="text-xs text-blue-600 font-medium mt-1">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                </div>
              ))}
            </div>
            <div className="p-6 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all"><Plus size={20} /> Новый проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] flex flex-col shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-blue-50/30">
              <h2 className="text-xl font-bold">Список для поиска (Семена)</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-2 hover:bg-blue-100 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 bg-white">
               <div className="flex flex-col gap-2">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-400 bg-blue-50/30' : 'border-gray-50 hover:border-blue-200'}`}>
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-5 w-5 text-blue-600 rounded" />
                     <span className="text-base font-semibold text-gray-800">{k.text}</span>
                   </label>
                 ))}
               </div>
            </div>

            <div className="p-6 bg-gray-50 border-t space-y-4">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-5 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-2xl font-black text-xl flex items-center justify-center gap-4 transition-all uppercase tracking-widest"
                >
                  {loading ? <Loader2 className="animate-spin" size={28} /> : <Play size={28} fill="currentColor" />}
                  Начать сбор запросов
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    // Strict exact-match lookup (ignoring leading/trailing spaces and casing)
    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      // Skip only if string is IDENTICAL. 
      // Swapped words like "buy car" vs "car buy" or inflections like "buy" vs "buying" 
      // result in different strings and won't be caught by this exact Set lookup.
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);
    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) allIds.forEach(id => currentSelection.delete(id));
    else allIds.forEach(id => currentSelection.add(id));

    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header - Reverted to Clean State */}
