                  <div className="absolute bottom-full mb-3 left-0 w-64 bg-white border border-gray-200 rounded-2xl shadow-2xl hidden group-hover:block p-3 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-60 overflow-y-auto space-y-1 mb-2">
