                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-3 py-3 px-8 bg-gray-100 text-gray-700 rounded-2xl text-sm font-black hover:bg-gray-200 transition-all uppercase tracking-widest border border-gray-200">
                  <Trash2 size={20} /> Удалить
