        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl w-full max-w-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-6 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-4">
                    <div className="p-3 bg-blue-600 text-white rounded-2xl"><Upload size={24} /></div>
                    <div>
                       <h2 className="text-xl font-bold text-blue-900">Массовая загрузка</h2>
                       <p className="text-sm text-blue-400">Вставьте список или загрузите файл (.txt)</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-2 hover:bg-blue-100 rounded-full transition-colors"><X size={24} /></button>
              </div>
              <div className="p-6 space-y-6">
                 <div className="flex gap-4">
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="flex-1 py-3 px-4 bg-white border-2 border-dashed border-gray-300 rounded-2xl flex flex-col items-center justify-center gap-2 hover:border-blue-400 hover:bg-blue-50 transition-all"
                    >
                       <FileText size={32} className="text-gray-400" />
                       <span className="text-sm font-bold text-gray-600">Выбрать файл</span>
                       <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                    </button>
                 </div>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Введите каждое слово с новой строки..."
                     className="w-full h-64 p-4 border-2 border-gray-100 rounded-2xl focus:border-blue-500 outline-none font-mono text-sm resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-4 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-blue-200 uppercase tracking-widest"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-xl font-bold text-gray-800">Мои Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={24} />
              </button>
            </div>
            <div className="p-4 max-h-[60vh] overflow-y-auto space-y-3">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-500 bg-blue-50 shadow-md' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="font-bold text-gray-800">{p.name}</h3>
                    <p className="text-xs text-blue-600 font-medium mt-1">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                </div>
              ))}
            </div>
            <div className="p-6 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all"><Plus size={20} /> Новый проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] flex flex-col shadow-2xl overflow-hidden border border-gray-100">
            <div className="p-6 border-b flex justify-between items-center bg-blue-50/30">
              <h2 className="text-xl font-bold">Список для поиска (Семена)</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-2 hover:bg-blue-100 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 bg-white">
               <div className="flex flex-col gap-2">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-400 bg-blue-50/30' : 'border-gray-50 hover:border-blue-200'}`}>
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-5 w-5 text-blue-600 rounded" />
                     <span className="text-base font-semibold text-gray-800">{k.text}</span>
                   </label>
                 ))}
               </div>
            </div>

            <div className="p-6 bg-gray-50 border-t space-y-4">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-5 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-2xl font-black text-xl flex items-center justify-center gap-4 transition-all uppercase tracking-widest"
                >
                  {loading ? <Loader2 className="animate-spin" size={28} /> : <Play size={28} fill="currentColor" />}
                  Начать сбор запросов
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);
    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) allIds.forEach(id => currentSelection.delete(id));
    else allIds.forEach(id => currentSelection.add(id));

    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-4 border-b border-gray-100 space-y-4">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-xs tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-xs text-red-500 hover:underline flex items-center gap-1">
                <MinusSquare size={12} /> Минус-слова
              </button>
            </div>

            <div className="flex gap-2">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика бизнеса..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-3 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-2 rounded-lg border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-500 border-blue-600'}`}
                title="Подобрать ключевые слова через ИИ"
              >
                {loading ? <Loader2 className="animate-spin" size={20} /> : <Search size={20} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1.5 text-xs bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-medium flex items-center justify-center gap-2">
              <List size={14} /> Отобранные слова ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-2 space-y-1 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-3">
                 <Loader2 className="animate-spin text-blue-500" size={32} />
                 <p className="text-sm text-gray-500">ИИ подбирает лучшие запросы...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-10 px-4">
                <p className="text-sm text-gray-400">Введите тематику и нажмите на лупу</p>
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-1.5 rounded hover:bg-white hover:shadow-sm border border-transparent hover:border-gray-200 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-2.5 h-3.5 w-3.5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-xs text-gray-700 flex-1 truncate">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-3 bg-white border-t border-gray-200 space-y-2 animate-in slide-in-from-bottom-5">
              <p className="text-[10px] text-gray-400 uppercase font-black text-center">Выбрано: {selection.size}</p>
              <div className="grid grid-cols-1 gap-1.5">
                <button onClick={() => moveKeywords('selected')} className="flex items-center justify-center gap-2 py-1.5 px-3 bg-blue-50 text-blue-700 rounded text-xs font-bold border border-blue-100 hover:bg-blue-100 transition-colors">
                  <ArrowRight size={12} /> В список для поиска
                </button>
                <div className="grid grid-cols-2 gap-1.5">
                  <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-2 py-1.5 px-3 bg-red-50 text-red-700 rounded text-xs font-bold border border-red-100 hover:bg-red-100 transition-colors">
                    <MinusSquare size={12} /> В минус
                  </button>
                  <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-2 py-1.5 px-3 bg-gray-50 text-gray-700 rounded text-xs font-bold border border-gray-100 hover:bg-gray-100 transition-colors">
                    <Trash2 size={12} /> Удалить
                  </button>
                </div>
              </div>
            </div>
          )}

          <div className="p-2 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={16} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
                >
                <BrainCircuit size={14} /> Умный отбор
              </button>

              <button 
                onClick={() => setShowBulkAdd(true)}
                disabled={!currentProject}
                className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
              >
                <Upload size={14} /> Добавить список
              </button>

              <div className="h-5 w-px bg-gray-200 mx-1" />

              <div className="flex items-center gap-2">
                <div className="relative w-56">
                  <input 
                    type="text" 
                    placeholder="Поиск..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-8 pr-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs focus:outline-none focus:ring-1 focus:ring-blue-500"
                  />
                  <Search className="absolute left-2.5 top-2 text-gray-400" size={14} />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-1.5 hover:bg-gray-100 rounded text-gray-600 border border-gray-200 flex items-center gap-1.5 text-xs font-bold">
                <Plus size={14} /> Группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {!currentProject ? (
              <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Создайте проект, чтобы начать</p>
                <button onClick={() => createProject()} className="px-5 py-2 bg-blue-600 text-white rounded-full text-xs font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-3">
                <Search size={40} className="text-gray-200" />
                <p className="text-xs font-medium uppercase tracking-wider">Спаршенных слов пока нет</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center px-1">
                  <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Результаты ({filteredKeywords('parsed').length})</h3>
                  <div className="flex items-center gap-1.5">
                    <button onClick={() => setSortOrder('asc')} className={`p-1 rounded ${sortOrder === 'asc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortAsc size={12}/></button>
                    <button onClick={() => setSortOrder('desc')} className={`p-1 rounded ${sortOrder === 'desc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortDesc size={12}/></button>
                  </div>
                </div>

                {/* Groups Display - More Compact */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    if (groupKeywords.length === 0 && searchQuery) return null;
                    return (
                      <div key={group.id} className="bg-white rounded-lg border border-gray-200 shadow-sm flex flex-col max-h-64">
                        <div className="p-2 border-b flex justify-between items-center bg-blue-50/40 rounded-t-lg">
                          <span className="text-xs font-bold text-slate-700 truncate">{group.name}</span>
                          <span className="text-[9px] bg-white px-1.5 py-0.5 rounded border border-blue-100 font-black text-blue-600 shadow-xs">{groupKeywords.length}</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className={`flex items-center px-2 py-1 rounded transition-colors cursor-pointer ${selection.has(k.id) ? 'bg-blue-50' : 'hover:bg-gray-50'}`}>
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 text-blue-600 rounded" />
                              <span className={`text-[11px] leading-tight ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'} font-medium`}>{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Main Results (Ungrouped) - Much More Compact */}
                <div className="w-full">
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                    <div className="px-3 py-2 border-b flex justify-between items-center bg-gray-50/80">
                      <div className="flex items-center gap-2">
                        <Layers size={14} className="text-gray-400" />
                        <span className="text-[10px] font-black text-gray-500 uppercase tracking-wider">Основные результаты</span>
                      </div>
                      <span className="text-[10px] font-bold text-gray-400">{filteredKeywords('parsed').filter(k => !k.groupId).length} слов</span>
                    </div>

                    <div className="p-2 flex flex-col gap-1">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <label key={k.id} className={`flex items-center py-1.5 px-3 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'bg-blue-50 border-blue-200 shadow-xs' : 'bg-white border-gray-100 hover:border-gray-300 hover:shadow-xs'}`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className={`text-xs font-medium flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions - Compact version */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-4 bg-white/95 backdrop-blur-md border-t border-gray-200 shadow-2xl flex items-center justify-center gap-4 z-40 animate-in slide-in-from-bottom-5">
                <div className="flex flex-col text-center px-2">
                  <span className="text-[9px] text-gray-400 uppercase font-black">Выбрано</span>
                  <span className="text-lg font-black text-blue-600 leading-none">{selection.size}</span>
                </div>

                <div className="h-8 w-px bg-gray-200" />

                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-2 px-5 bg-red-600 text-white rounded-lg text-xs font-bold hover:bg-red-700 transition-all shadow-md uppercase">
                  <MinusSquare size={16} /> Минус
                </button>

                <div className="relative group">
                  <button className="flex items-center gap-2 py-2 px-5 bg-blue-600 text-white rounded-lg text-xs font-bold hover:bg-blue-700 transition-all shadow-md uppercase">
                    <Layers size={16} /> В группу <ChevronDown size={14} />
                  </button>
                  <div className="absolute bottom-full mb-2 left-0 w-56 bg-white border border-gray-200 rounded-lg shadow-xl hidden group-hover:block p-2 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-48 overflow-y-auto space-y-0.5">
                      {currentProject?.groups.map(g => (
                        <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-1.5 text-[11px] hover:bg-blue-50 rounded font-bold text-gray-600 transition-colors">
                          {g.name}
                        </button>
                      ))}
                    </div>
                    <div className="h-px bg-gray-100 my-1.5" />
                    <button onClick={createGroup} className="w-full text-center p-1.5 text-[10px] text-blue-600 font-black hover:bg-blue-50 rounded uppercase border border-dashed border-blue-200">
                      + Новая группа
                    </button>
                  </div>
                </div>

                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-2 px-5 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-all uppercase border border-gray-200">
                  <Trash2 size={16} /> Удалить
                </button>

                <button onClick={() => setSelection(new Set())} className="p-2 bg-gray-50 hover:bg-red-50 hover:text-red-500 rounded-lg text-gray-400 transition-all border border-gray-100">
                  <X size={18} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-5 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-3">
                    <div className="p-2 bg-blue-600 text-white rounded-lg"><Upload size={20} /></div>
                    <div>
                       <h2 className="text-lg font-bold text-blue-900 leading-tight">Загрузка слов</h2>
                       <p className="text-[10px] text-blue-400 uppercase font-bold">Список или текстовый файл</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-1.5 hover:bg-blue-100 rounded-full transition-colors"><X size={20} /></button>
              </div>
              <div className="p-6 space-y-5">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full py-4 bg-white border-2 border-dashed border-gray-200 rounded-xl flex items-center justify-center gap-3 hover:border-blue-400 hover:bg-blue-50 transition-all"
                  >
                    <FileText size={24} className="text-gray-400" />
                    <span className="text-sm font-bold text-gray-600">Выбрать .txt файл</span>
                    <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                 </button>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Вставьте слова по одному на строку..."
                     className="w-full h-48 p-3 border border-gray-200 rounded-xl focus:ring-1 focus:ring-blue-500 outline-none font-mono text-xs resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-3.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-xl font-black text-sm transition-all shadow-lg uppercase tracking-wider"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-sm shadow-2xl overflow-hidden">
            <div className="p-5 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-base font-bold text-gray-800 uppercase tracking-tight">Ваши Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="p-3 max-h-[50vh] overflow-y-auto space-y-2">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-400 bg-blue-50' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="text-sm font-bold text-gray-800 truncate">{p.name}</h3>
                    <p className="text-[10px] text-blue-600 font-bold uppercase mt-0.5">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-1.5 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
            <div className="p-4 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold flex items-center justify-center gap-2 uppercase tracking-wide transition-all"><Plus size={16} /> Создать проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[70vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-5 border-b flex justify-between items-center bg-blue-50/40">
              <h2 className="text-base font-bold uppercase tracking-tight">Семантические семена</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-1.5 hover:bg-blue-100 rounded-full transition-colors"><X size={20} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 bg-white space-y-1">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className={`flex items-center gap-3 p-2.5 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-300 bg-blue-50' : 'border-gray-50 hover:border-blue-100'}`}>
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-4 w-4 text-blue-600 rounded" />
                     <span className="text-sm font-semibold text-gray-800">{k.text}</span>
                   </label>
                 ))}
            </div>

            <div className="p-5 bg-gray-50 border-t space-y-3">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-4 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-xl font-black text-sm flex items-center justify-center gap-3 transition-all uppercase tracking-widest"
                >
                  {loading ? <Loader2 className="animate-spin" size={20} /> : <Play size={20} fill="currentColor" />}
                  Начать расширение
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAllSelected = () => {
    if (!currentProject) return;
    const selectedKeywords = currentProject.keywords.filter(k => k.status === 'selected');
    const allIds = selectedKeywords.map(k => k.id);
    const currentSelection = new Set(selection);
    const allIn = allIds.every(id => currentSelection.has(id));

    if (allIn) allIds.forEach(id => currentSelection.delete(id));
    else allIds.forEach(id => currentSelection.add(id));

    setSelection(currentSelection);
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const deleteProject = (id: string) => {
    setProjects(prev => prev.filter(p => p.id !== id));
    if (currentProjectId === id) setCurrentProjectId(null);
    setProjectToDeleteId(null);
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection - Even more compact */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-3 border-b border-gray-100 space-y-3">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-[10px] tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-[10px] text-red-500 hover:underline flex items-center gap-1 font-bold">
                <MinusSquare size={10} /> Минус-слова
              </button>
            </div>

            <div className="flex gap-1.5">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-2.5 pr-2.5 py-1.5 border border-gray-200 rounded text-xs focus:ring-1 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-1.5 rounded border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-50 border-blue-600'}`}
              >
                {loading ? <Loader2 className="animate-spin" size={14} /> : <Search size={14} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1 text-[10px] bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-black flex items-center justify-center gap-1.5 uppercase">
              <List size={12} /> Отобранные ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-2">
                 <Loader2 className="animate-spin text-blue-500" size={24} />
                 <p className="text-[10px] text-gray-500 uppercase font-bold">Подбор запросов...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-8 px-4">
                <p className="text-[10px] text-gray-400 uppercase font-bold">Нет данных</p>
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-1 rounded hover:bg-white hover:shadow-xs border border-transparent hover:border-gray-100 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-2 h-3 w-3 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-[11px] text-gray-600 flex-1 truncate font-medium">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-2 bg-white border-t border-gray-200 space-y-1 animate-in slide-in-from-bottom-5">
              <p className="text-[9px] text-gray-400 uppercase font-black text-center mb-1">Выбрано: {selection.size}</p>
              <button onClick={() => moveKeywords('selected')} className="w-full flex items-center justify-center gap-1.5 py-1 px-3 bg-blue-50 text-blue-700 rounded text-[10px] font-black border border-blue-100 hover:bg-blue-100 transition-colors uppercase">
                <ArrowRight size={10} /> В семена
              </button>
              <div className="grid grid-cols-2 gap-1">
                <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-1 py-1 px-3 bg-red-50 text-red-700 rounded text-[10px] font-black border border-red-100 hover:bg-red-100 transition-colors uppercase">
                  <MinusSquare size={10} /> Минус
                </button>
                <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-1 py-1 px-3 bg-gray-50 text-gray-700 rounded text-[10px] font-black border border-gray-100 hover:bg-gray-100 transition-colors uppercase">
                  <Trash2 size={10} /> Удал.
                </button>
              </div>
            </div>
          )}

          <div className="p-1 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={14} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
                >
                <BrainCircuit size={14} /> Умный отбор
              </button>

              <button 
                onClick={() => setShowBulkAdd(true)}
                disabled={!currentProject}
                className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
              >
                <Upload size={14} /> Добавить список
              </button>

              <div className="h-5 w-px bg-gray-200 mx-1" />

              <div className="flex items-center gap-2">
                <div className="relative w-56">
                  <input 
                    type="text" 
                    placeholder="Поиск..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-8 pr-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs focus:outline-none focus:ring-1 focus:ring-blue-500"
                  />
                  <Search className="absolute left-2.5 top-2 text-gray-400" size={14} />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-1.5 hover:bg-gray-100 rounded text-gray-600 border border-gray-200 flex items-center gap-1.5 text-xs font-bold">
                <Plus size={14} /> Группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {!currentProject ? (
              <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Создайте проект, чтобы начать</p>
                <button onClick={() => createProject()} className="px-5 py-2 bg-blue-600 text-white rounded-full text-xs font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-3">
                <Search size={40} className="text-gray-200" />
                <p className="text-xs font-medium uppercase tracking-wider">Спаршенных слов пока нет</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center px-1">
                  <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Результаты ({filteredKeywords('parsed').length})</h3>
                  <div className="flex items-center gap-1.5">
                    <button onClick={() => setSortOrder('asc')} className={`p-1 rounded ${sortOrder === 'asc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortAsc size={12}/></button>
                    <button onClick={() => setSortOrder('desc')} className={`p-1 rounded ${sortOrder === 'desc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortDesc size={12}/></button>
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    if (groupKeywords.length === 0 && searchQuery) return null;
                    return (
                      <div key={group.id} className="bg-white rounded-lg border border-gray-200 shadow-sm flex flex-col max-h-64">
                        <div className="p-2 border-b flex justify-between items-center bg-blue-50/40 rounded-t-lg">
                          <span className="text-xs font-bold text-slate-700 truncate">{group.name}</span>
                          <span className="text-[9px] bg-white px-1.5 py-0.5 rounded border border-blue-100 font-black text-blue-600 shadow-xs">{groupKeywords.length}</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className={`flex items-center px-2 py-1 rounded transition-colors cursor-pointer ${selection.has(k.id) ? 'bg-blue-50' : 'hover:bg-gray-50'}`}>
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 text-blue-600 rounded" />
                              <span className={`text-[11px] leading-tight ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'} font-medium`}>{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <div className="w-full">
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                    <div className="px-3 py-2 border-b flex justify-between items-center bg-gray-50/80">
                      <div className="flex items-center gap-2">
                        <Layers size={14} className="text-gray-400" />
                        <span className="text-[10px] font-black text-gray-500 uppercase tracking-wider">Основные результаты</span>
                      </div>
                      <span className="text-[10px] font-bold text-gray-400">{filteredKeywords('parsed').filter(k => !k.groupId).length} слов</span>
                    </div>

                    <div className="p-2 flex flex-col gap-1">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <label key={k.id} className={`flex items-center py-1.5 px-3 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'bg-blue-50 border-blue-200 shadow-xs' : 'bg-white border-gray-100 hover:border-gray-300 hover:shadow-xs'}`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className={`text-xs font-medium flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-4 bg-white/95 backdrop-blur-md border-t border-gray-200 shadow-2xl flex items-center justify-center gap-4 z-40 animate-in slide-in-from-bottom-5">
                <div className="flex flex-col text-center px-2">
                  <span className="text-[9px] text-gray-400 uppercase font-black">Выбрано</span>
                  <span className="text-lg font-black text-blue-600 leading-none">{selection.size}</span>
                </div>

                <div className="h-8 w-px bg-gray-200" />

                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-2 px-5 bg-red-600 text-white rounded-lg text-xs font-bold hover:bg-red-700 transition-all shadow-md uppercase">
                  <MinusSquare size={16} /> Минус
                </button>

                <div className="relative group">
                  <button className="flex items-center gap-2 py-2 px-5 bg-blue-600 text-white rounded-lg text-xs font-bold hover:bg-blue-700 transition-all shadow-md uppercase">
                    <Layers size={16} /> В группу <ChevronDown size={14} />
                  </button>
                  <div className="absolute bottom-full mb-2 left-0 w-56 bg-white border border-gray-200 rounded-lg shadow-xl hidden group-hover:block p-2 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-48 overflow-y-auto space-y-0.5">
                      {currentProject?.groups.map(g => (
                        <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-1.5 text-[11px] hover:bg-blue-50 rounded font-bold text-gray-600 transition-colors">
                          {g.name}
                        </button>
                      ))}
                    </div>
                    <div className="h-px bg-gray-100 my-1.5" />
                    <button onClick={createGroup} className="w-full text-center p-1.5 text-[10px] text-blue-600 font-black hover:bg-blue-50 rounded uppercase border border-dashed border-blue-200">
                      + Новая группа
                    </button>
                  </div>
                </div>

                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-2 px-5 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-all uppercase border border-gray-200">
                  <Trash2 size={16} /> Удалить
                </button>

                <button onClick={() => setSelection(new Set())} className="p-2 bg-gray-50 hover:bg-red-50 hover:text-red-500 rounded-lg text-gray-400 transition-all border border-gray-100">
                  <X size={18} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-5 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-3">
                    <div className="p-2 bg-blue-600 text-white rounded-lg"><Upload size={20} /></div>
                    <div>
                       <h2 className="text-lg font-bold text-blue-900 leading-tight">Загрузка слов</h2>
                       <p className="text-[10px] text-blue-400 uppercase font-bold">Список или текстовый файл</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-1.5 hover:bg-blue-100 rounded-full transition-colors"><X size={20} /></button>
              </div>
              <div className="p-6 space-y-5">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full py-4 bg-white border-2 border-dashed border-gray-200 rounded-xl flex items-center justify-center gap-3 hover:border-blue-400 hover:bg-blue-50 transition-all"
                  >
                    <FileText size={24} className="text-gray-400" />
                    <span className="text-sm font-bold text-gray-600">Выбрать .txt файл</span>
                    <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                 </button>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Вставьте слова по одному на строку..."
                     className="w-full h-48 p-3 border border-gray-200 rounded-xl focus:ring-1 focus:ring-blue-500 outline-none font-mono text-xs resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-3.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-xl font-black text-sm transition-all shadow-lg uppercase tracking-wider"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-sm shadow-2xl overflow-hidden">
            <div className="p-5 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-base font-bold text-gray-800 uppercase tracking-tight">Ваши Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="p-3 max-h-[50vh] overflow-y-auto space-y-2">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-400 bg-blue-50' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="text-sm font-bold text-gray-800 truncate">{p.name}</h3>
                    <p className="text-[10px] text-blue-600 font-bold uppercase mt-0.5">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-1.5 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
            <div className="p-4 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold flex items-center justify-center gap-2 uppercase tracking-wide transition-all"><Plus size={16} /> Создать проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal - More compact now */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[75vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-blue-50/40">
              <h2 className="text-xs font-black uppercase tracking-widest text-blue-900">Семантические семена</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-1 hover:bg-blue-100 rounded-full transition-colors"><X size={18} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-2 bg-white space-y-0.5">
                 {currentProject?.keywords.filter(k => k.status === 'selected').length === 0 ? (
                   <div className="flex flex-col items-center justify-center py-20 text-gray-400 italic text-[11px]">
                     Нет выбранных слов для семян
                   </div>
                 ) : (
                   currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                     <label key={k.id} className={`flex items-center gap-2.5 px-3 py-1.5 rounded-md border transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-200 bg-blue-50' : 'border-gray-50 hover:border-gray-200 hover:bg-gray-50'}`}>
                       <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-3.5 w-3.5 text-blue-600 rounded" />
                       <span className="text-xs font-medium text-gray-700">{k.text}</span>
                     </label>
                   ))
                 )}
            </div>

            <div className="p-4 bg-gray-50 border-t space-y-2">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-3 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-lg font-black text-xs flex items-center justify-center gap-2.5 transition-all uppercase tracking-widest shadow-md"
                >
                  {loading ? <Loader2 className="animate-spin" size={16} /> : <Play size={16} fill="currentColor" />}
                  Запустить расширение ({currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length})
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList, Scissors
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Analysis state
  const [expandedWords, setExpandedWords] = useState<Set<string>>(new Set());

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  // Word Analysis Logic
  const wordAnalysisMap = useMemo(() => {
    const map: Record<string, string[]> = {};
    const parsed = filteredKeywords('parsed');

    parsed.forEach(k => {
      // Clean and split phrase into words
      const words = k.text.toLowerCase().split(/[^a-zа-я0-9]/).filter(w => w.length > 1);
      const uniqueInPhrase = Array.from(new Set(words));
      uniqueInPhrase.forEach(w => {
        if (!map[w]) map[w] = [];
        map[w].push(k.id);
      });
    });

    return Object.entries(map).sort((a, b) => b[1].length - a[1].length);
  }, [currentProject?.keywords, searchQuery]);

  const toggleWordSelection = (word: string, keywordIds: string[]) => {
    const next = new Set(selection);
    const allSelected = keywordIds.every(id => next.has(id));

    if (allSelected) {
      keywordIds.forEach(id => next.delete(id));
    } else {
      keywordIds.forEach(id => next.add(id));
    }
    setSelection(next);
  };

  const toggleWordExpand = (word: string) => {
    const next = new Set(expandedWords);
    if (next.has(word)) next.delete(word);
    else next.add(word);
    setExpandedWords(next);
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-3 border-b border-gray-100 space-y-3">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-[10px] tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-[10px] text-red-500 hover:underline flex items-center gap-1 font-bold">
                <MinusSquare size={10} /> Минус-слова
              </button>
            </div>

            <div className="flex gap-1.5">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-2.5 pr-2.5 py-1.5 border border-gray-200 rounded text-xs focus:ring-1 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-1.5 rounded border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-50 border-blue-600'}`}
              >
                {loading ? <Loader2 className="animate-spin" size={14} /> : <Search size={14} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1 text-[10px] bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-black flex items-center justify-center gap-1.5 uppercase">
              <List size={12} /> Отобранные ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-2">
                 <Loader2 className="animate-spin text-blue-500" size={24} />
                 <p className="text-[10px] text-gray-500 uppercase font-bold">Подбор запросов...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-8 px-4">
                <p className="text-[10px] text-gray-400 uppercase font-bold">Нет данных</p>
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-1 rounded hover:bg-white hover:shadow-xs border border-transparent hover:border-gray-100 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-2 h-3 w-3 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-[11px] text-gray-600 flex-1 truncate font-medium">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-2 bg-white border-t border-gray-200 space-y-1 animate-in slide-in-from-bottom-5">
              <p className="text-[9px] text-gray-400 uppercase font-black text-center mb-1">Выбрано: {selection.size}</p>
              <button onClick={() => moveKeywords('selected')} className="w-full flex items-center justify-center gap-1.5 py-1 px-3 bg-blue-50 text-blue-700 rounded text-[10px] font-black border border-blue-100 hover:bg-blue-100 transition-colors uppercase">
                <ArrowRight size={10} /> В семена
              </button>
              <div className="grid grid-cols-2 gap-1">
                <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-1 py-1 px-3 bg-red-50 text-red-700 rounded text-[10px] font-black border border-red-100 hover:bg-red-100 transition-colors uppercase">
                  <MinusSquare size={10} /> Минус
                </button>
                <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-1 py-1 px-3 bg-gray-50 text-gray-700 rounded text-[10px] font-black border border-gray-100 hover:bg-gray-100 transition-colors uppercase">
                  <Trash2 size={10} /> Удал.
                </button>
              </div>
            </div>
          )}

          <div className="p-1 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={14} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
                >
                <BrainCircuit size={14} /> Умный отбор
              </button>

              <button 
                onClick={() => setShowBulkAdd(true)}
                disabled={!currentProject}
                className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
              >
                <Upload size={14} /> Добавить список
              </button>

              <div className="h-5 w-px bg-gray-200 mx-1" />

              <div className="flex items-center gap-2">
                <div className="relative w-56">
                  <input 
                    type="text" 
                    placeholder="Поиск..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-8 pr-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs focus:outline-none focus:ring-1 focus:ring-blue-500"
                  />
                  <Search className="absolute left-2.5 top-2 text-gray-400" size={14} />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-1.5 hover:bg-gray-100 rounded text-gray-600 border border-gray-200 flex items-center gap-1.5 text-xs font-bold">
                <Plus size={14} /> Группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {!currentProject ? (
              <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Создайте проект, чтобы начать</p>
                <button onClick={() => createProject()} className="px-5 py-2 bg-blue-600 text-white rounded-full text-xs font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-3">
                <Search size={40} className="text-gray-200" />
                <p className="text-xs font-medium uppercase tracking-wider">Спаршенных слов пока нет</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center px-1">
                  <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Результаты ({filteredKeywords('parsed').length})</h3>
                  <div className="flex items-center gap-1.5">
                    <button onClick={() => setSortOrder('asc')} className={`p-1 rounded ${sortOrder === 'asc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortAsc size={12}/></button>
                    <button onClick={() => setSortOrder('desc')} className={`p-1 rounded ${sortOrder === 'desc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortDesc size={12}/></button>
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    if (groupKeywords.length === 0 && searchQuery) return null;
                    return (
                      <div key={group.id} className="bg-white rounded-lg border border-gray-200 shadow-sm flex flex-col max-h-64">
                        <div className="p-2 border-b flex justify-between items-center bg-blue-50/40 rounded-t-lg">
                          <span className="text-xs font-bold text-slate-700 truncate">{group.name}</span>
                          <span className="text-[9px] bg-white px-1.5 py-0.5 rounded border border-blue-100 font-black text-blue-600 shadow-xs">{groupKeywords.length}</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className={`flex items-center px-2 py-1 rounded transition-colors cursor-pointer ${selection.has(k.id) ? 'bg-blue-50' : 'hover:bg-gray-50'}`}>
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 text-blue-600 rounded" />
                              <span className={`text-[11px] leading-tight ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'} font-medium`}>{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <div className="w-full">
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                    <div className="px-3 py-2 border-b flex justify-between items-center bg-gray-50/80">
                      <div className="flex items-center gap-2">
                        <Layers size={14} className="text-gray-400" />
                        <span className="text-[10px] font-black text-gray-500 uppercase tracking-wider">Основные результаты</span>
                      </div>
                      <span className="text-[10px] font-bold text-gray-400">{filteredKeywords('parsed').filter(k => !k.groupId).length} слов</span>
                    </div>

                    <div className="p-2 flex flex-col gap-1">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <label key={k.id} className={`flex items-center py-1.5 px-3 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'bg-blue-50 border-blue-200 shadow-xs' : 'bg-white border-gray-100 hover:border-gray-300 hover:shadow-xs'}`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className={`text-xs font-medium flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-4 bg-white/95 backdrop-blur-md border-t border-gray-200 shadow-2xl flex items-center justify-center gap-4 z-40 animate-in slide-in-from-bottom-5">
                <div className="flex flex-col text-center px-2">
                  <span className="text-[9px] text-gray-400 uppercase font-black">Выбрано</span>
                  <span className="text-lg font-black text-blue-600 leading-none">{selection.size}</span>
                </div>

                <div className="h-8 w-px bg-gray-200" />

                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-2 px-5 bg-red-600 text-white rounded-lg text-xs font-bold hover:bg-red-700 transition-all shadow-md uppercase">
                  <MinusSquare size={16} /> Минус
                </button>

                <div className="relative group">
                  <button className="flex items-center gap-2 py-2 px-5 bg-blue-600 text-white rounded-lg text-xs font-bold hover:bg-blue-700 transition-all shadow-md uppercase">
                    <Layers size={16} /> В группу <ChevronDown size={14} />
                  </button>
                  <div className="absolute bottom-full mb-2 left-0 w-56 bg-white border border-gray-200 rounded-lg shadow-xl hidden group-hover:block p-2 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-48 overflow-y-auto space-y-0.5">
                      {currentProject?.groups.map(g => (
                        <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-1.5 text-[11px] hover:bg-blue-50 rounded font-bold text-gray-600 transition-colors">
                          {g.name}
                        </button>
                      ))}
                    </div>
                    <div className="h-px bg-gray-100 my-1.5" />
                    <button onClick={createGroup} className="w-full text-center p-1.5 text-[10px] text-blue-600 font-black hover:bg-blue-50 rounded uppercase border border-dashed border-blue-200">
                      + Новая группа
                    </button>
                  </div>
                </div>

                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-2 px-5 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-all uppercase border border-gray-200">
                  <Trash2 size={16} /> Удалить
                </button>

                <button onClick={() => setSelection(new Set())} className="p-2 bg-gray-50 hover:bg-red-50 hover:text-red-500 rounded-lg text-gray-400 transition-all border border-gray-100">
                  <X size={18} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Word Analysis Modal */}
      {showAnalysis && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-2xl h-[85vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
             <div className="p-6 border-b flex justify-between items-center bg-indigo-50">
                <div className="flex items-center gap-3">
                   <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-lg"><Scissors size={24} /></div>
                   <div>
                      <h2 className="text-xl font-black text-indigo-900 leading-tight">Анализ по словам</h2>
                      <p className="text-[10px] text-indigo-400 uppercase font-black tracking-widest">Разбивка фраз на части</p>
                   </div>
                </div>
                <button onClick={() => setShowAnalysis(false)} className="p-2 hover:bg-indigo-100 rounded-full transition-colors"><X size={24} /></button>
             </div>

             <div className="flex-1 overflow-y-auto p-4 space-y-2 bg-gray-50/50">
                {wordAnalysisMap.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-4">
                    <Search size={48} />
                    <p className="text-sm font-bold uppercase tracking-widest">Нет данных для анализа</p>
                  </div>
                ) : (
                  wordAnalysisMap.map(([word, ids]) => {
                    const isExpanded = expandedWords.has(word);
                    const allInSelection = ids.every(id => selection.has(id));
                    const someInSelection = ids.some(id => selection.has(id));

                    return (
                      <div key={word} className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden transition-all">
                        <div className="flex items-center p-3 hover:bg-gray-50 transition-colors">
                          <input 
                            type="checkbox" 
                            checked={allInSelection}
                            ref={el => el && (el.indeterminate = someInSelection && !allInSelection)}
                            onChange={() => toggleWordSelection(word, ids)}
                            className="mr-4 h-5 w-5 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
                          />
                          <div className="flex-1 flex items-center justify-between cursor-pointer" onClick={() => toggleWordExpand(word)}>
                            <div className="flex flex-col">
                              <span className="text-sm font-black text-slate-700 capitalize">{word}</span>
                              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{ids.length} вхождений</span>
                            </div>
                            <div className="flex items-center gap-3">
                              {isExpanded ? <ChevronDown size={18} className="text-slate-400" /> : <ChevronRight size={18} className="text-slate-400" />}
                            </div>
                          </div>
                        </div>

                        {isExpanded && (
                          <div className="px-12 py-3 bg-gray-50/80 border-t border-gray-100 space-y-1.5">
                            {ids.map(id => {
                              const k = currentProject?.keywords.find(item => item.id === id);
                              if (!k) return null;
                              return (
                                <label key={id} className="flex items-center gap-3 group cursor-pointer">
                                  <input 
                                    type="checkbox" 
                                    checked={selection.has(id)} 
                                    onChange={() => toggleSelect(id)} 
                                    className="h-4 w-4 text-indigo-500 rounded border-gray-300" 
                                  />
                                  <span className="text-[11px] font-medium text-slate-500 group-hover:text-indigo-600 transition-colors">{k.text}</span>
                                </label>
                              );
                            })}
                          </div>
                        )}
                      </div>
                    );
                  })
                )}
             </div>

             {selection.size > 0 && (
               <div className="p-6 bg-white border-t border-gray-100 flex items-center justify-between gap-4">
                  <div className="flex flex-col">
                    <span className="text-[10px] text-slate-400 uppercase font-black">Выбрано запросов</span>
                    <span className="text-xl font-black text-indigo-600 leading-none">{selection.size}</span>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-3 px-6 bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg shadow-red-200 hover:bg-red-700 transition-all">
                      <MinusSquare size={16} /> В минус
                    </button>
                    <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-3 px-6 bg-slate-900 text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg shadow-slate-200 hover:bg-black transition-all">
                      <Trash2 size={16} /> Удалить
                    </button>
                  </div>
               </div>
             )}
          </div>
        </div>
      )}

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-5 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-3">
                    <div className="p-2 bg-blue-600 text-white rounded-lg"><Upload size={20} /></div>
                    <div>
                       <h2 className="text-lg font-bold text-blue-900 leading-tight">Загрузка слов</h2>
                       <p className="text-[10px] text-blue-400 uppercase font-bold">Список или текстовый файл</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-1.5 hover:bg-blue-100 rounded-full transition-colors"><X size={20} /></button>
              </div>
              <div className="p-6 space-y-5">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full py-4 bg-white border-2 border-dashed border-gray-200 rounded-xl flex items-center justify-center gap-3 hover:border-blue-400 hover:bg-blue-50 transition-all"
                  >
                    <FileText size={24} className="text-gray-400" />
                    <span className="text-sm font-bold text-gray-600">Выбрать .txt файл</span>
                    <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                 </button>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Вставьте слова по одному на строку..."
                     className="w-full h-48 p-3 border border-gray-200 rounded-xl focus:ring-1 focus:ring-blue-500 outline-none font-mono text-xs resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-3.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-xl font-black text-sm transition-all shadow-lg uppercase tracking-wider"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-sm shadow-2xl overflow-hidden">
            <div className="p-5 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-base font-bold text-gray-800 uppercase tracking-tight">Ваши Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="p-3 max-h-[50vh] overflow-y-auto space-y-2">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-400 bg-blue-50' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="text-sm font-bold text-gray-800 truncate">{p.name}</h3>
                    <p className="text-[10px] text-blue-600 font-bold uppercase mt-0.5">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-1.5 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
            <div className="p-4 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold flex items-center justify-center gap-2 uppercase tracking-wide transition-all"><Plus size={16} /> Создать проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal - Seeds */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[75vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-blue-50/40">
              <h2 className="text-xs font-black uppercase tracking-widest text-blue-900">Семантические семена</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-1 hover:bg-blue-100 rounded-full transition-colors"><X size={18} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-2 bg-white space-y-0.5">
                 {currentProject?.keywords.filter(k => k.status === 'selected').length === 0 ? (
                   <div className="flex flex-col items-center justify-center py-20 text-gray-400 italic text-[11px]">
                     Нет выбранных слов для семян
                   </div>
                 ) : (
                   currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                     <label key={k.id} className={`flex items-center gap-2.5 px-3 py-1.5 rounded-md border transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-200 bg-blue-50' : 'border-gray-50 hover:border-gray-200 hover:bg-gray-50'}`}>
                       <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-3.5 w-3.5 text-blue-600 rounded" />
                       <span className="text-xs font-medium text-gray-700">{k.text}</span>
                     </label>
                   ))
                 )}
            </div>

            <div className="p-4 bg-gray-50 border-t space-y-2">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-3 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-lg font-black text-xs flex items-center justify-center gap-2.5 transition-all uppercase tracking-widest shadow-md"
                >
                  {loading ? <Loader2 className="animate-spin" size={16} /> : <Play size={16} fill="currentColor" />}
                  Запустить расширение ({currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length})
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList, Scissors
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Analysis state
  const [expandedWords, setExpandedWords] = useState<Set<string>>(new Set());

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  // Word Analysis Logic
  const wordAnalysisMap = useMemo(() => {
    const map: Record<string, string[]> = {};
    const parsed = filteredKeywords('parsed');

    parsed.forEach(k => {
      // Clean and split phrase into words
      const words = k.text.toLowerCase().split(/[^a-zа-я0-9]/).filter(w => w.length > 1);
      // Fix: Use spread operator on Set to ensure type inference correctly identifies words as string[]
      const uniqueInPhrase = [...new Set(words)];
      uniqueInPhrase.forEach(w => {
        if (!map[w]) map[w] = [];
        map[w].push(k.id);
      });
    });

    return Object.entries(map).sort((a, b) => b[1].length - a[1].length);
  }, [currentProject?.keywords, searchQuery, filteredKeywords]);

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">

        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-3 border-b border-gray-100 space-y-3">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-[10px] tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-[10px] text-red-500 hover:underline flex items-center gap-1 font-bold">
                <MinusSquare size={10} /> Минус-слова
              </button>
            </div>

            <div className="flex gap-1.5">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-2.5 pr-2.5 py-1.5 border border-gray-200 rounded text-xs focus:ring-1 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                />
              </div>
              <button 
                onClick={triggerSuggestions}
                disabled={loading || !themeInput.trim()}
                className={`p-1.5 rounded border transition-all shadow-sm ${loading ? 'bg-gray-100 text-gray-400 border-gray-100' : 'bg-blue-600 text-white hover:bg-blue-50 border-blue-600'}`}
              >
                {loading ? <Loader2 className="animate-spin" size={14} /> : <Search size={14} />}
              </button>
            </div>

            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1 text-[10px] bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-black flex items-center justify-center gap-1.5 uppercase">
              <List size={12} /> Отобранные ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5 bg-gray-50/50">
            {loading && filteredKeywords('preliminary').length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 px-4 text-center space-y-2">
                 <Loader2 className="animate-spin text-blue-500" size={24} />
                 <p className="text-[10px] text-gray-500 uppercase font-bold">Подбор запросов...</p>
              </div>
            ) : filteredKeywords('preliminary').length === 0 ? (
              <div className="text-center py-8 px-4">
                <p className="text-[10px] text-gray-400 uppercase font-bold">Нет данных</p>
              </div>
            ) : (
              filteredKeywords('preliminary').map(k => (
                <div key={k.id} className="group flex items-center p-1 rounded hover:bg-white hover:shadow-xs border border-transparent hover:border-gray-100 transition-all">
                  <input 
                    type="checkbox" 
                    checked={selection.has(k.id)}
                    onChange={() => toggleSelect(k.id)}
                    className="mr-2 h-3 w-3 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="text-[11px] text-gray-600 flex-1 truncate font-medium">{k.text}</span>
                </div>
              ))
            )}
          </div>

          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'preliminary') && (
            <div className="p-2 bg-white border-t border-gray-200 space-y-1 animate-in slide-in-from-bottom-5">
              <p className="text-[9px] text-gray-400 uppercase font-black text-center mb-1">Выбрано: {selection.size}</p>
              <button onClick={() => moveKeywords('selected')} className="w-full flex items-center justify-center gap-1.5 py-1 px-3 bg-blue-50 text-blue-700 rounded text-[10px] font-black border border-blue-100 hover:bg-blue-100 transition-colors uppercase">
                <ArrowRight size={10} /> В семена
              </button>
              <div className="grid grid-cols-2 gap-1">
                <button onClick={() => moveKeywords('negative')} className="flex items-center justify-center gap-1 py-1 px-3 bg-red-50 text-red-700 rounded text-[10px] font-black border border-red-100 hover:bg-red-100 transition-colors uppercase">
                  <MinusSquare size={10} /> Минус
                </button>
                <button onClick={() => moveKeywords('trash')} className="flex items-center justify-center gap-1 py-1 px-3 bg-gray-50 text-gray-700 rounded text-[10px] font-black border border-gray-100 hover:bg-gray-100 transition-colors uppercase">
                  <Trash2 size={10} /> Удал.
                </button>
              </div>
            </div>
          )}

          <div className="p-1 border-t bg-white flex justify-between items-center">
            <button onClick={() => setShowTrash(true)} className="p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
              <Trash2 size={14} />
            </button>
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3 flex-1">
               <button 
                  onClick={runSmartFilter} 
                  disabled={loading || filteredKeywords('parsed').length === 0}
                  className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
                >
                <BrainCircuit size={14} /> Умный отбор
              </button>

              <button 
                onClick={() => setShowBulkAdd(true)}
                disabled={!currentProject}
                className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-300 text-white rounded text-xs font-bold transition-all shadow-sm"
              >
                <Upload size={14} /> Добавить список
              </button>

              <div className="h-5 w-px bg-gray-200 mx-1" />

              <div className="flex items-center gap-2">
                <div className="relative w-56">
                  <input 
                    type="text" 
                    placeholder="Поиск..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-8 pr-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs focus:outline-none focus:ring-1 focus:ring-blue-500"
                  />
                  <Search className="absolute left-2.5 top-2 text-gray-400" size={14} />
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button onClick={createGroup} className="p-1.5 hover:bg-gray-100 rounded text-gray-600 border border-gray-200 flex items-center gap-1.5 text-xs font-bold">
                <Plus size={14} /> Группа
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {!currentProject ? (
              <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-4">
                <Sparkles size={48} className="text-gray-200" />
                <p className="text-sm font-medium">Создайте проект, чтобы начать</p>
                <button onClick={() => createProject()} className="px-5 py-2 bg-blue-600 text-white rounded-full text-xs font-bold shadow-md">Создать проект</button>
              </div>
            ) : filteredKeywords('parsed').length === 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center py-20 text-gray-400 space-y-3">
                <Search size={40} className="text-gray-200" />
                <p className="text-xs font-medium uppercase tracking-wider">Спаршенных слов пока нет</p>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center px-1">
                  <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Результаты ({filteredKeywords('parsed').length})</h3>
                  <div className="flex items-center gap-1.5">
                    <button onClick={() => setSortOrder('asc')} className={`p-1 rounded ${sortOrder === 'asc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortAsc size={12}/></button>
                    <button onClick={() => setSortOrder('desc')} className={`p-1 rounded ${sortOrder === 'desc' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-400'}`}><SortDesc size={12}/></button>
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    if (groupKeywords.length === 0 && searchQuery) return null;
                    return (
                      <div key={group.id} className="bg-white rounded-lg border border-gray-200 shadow-sm flex flex-col max-h-64">
                        <div className="p-2 border-b flex justify-between items-center bg-blue-50/40 rounded-t-lg">
                          <span className="text-xs font-bold text-slate-700 truncate">{group.name}</span>
                          <span className="text-[9px] bg-white px-1.5 py-0.5 rounded border border-blue-100 font-black text-blue-600 shadow-xs">{groupKeywords.length}</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className={`flex items-center px-2 py-1 rounded transition-colors cursor-pointer ${selection.has(k.id) ? 'bg-blue-50' : 'hover:bg-gray-50'}`}>
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 text-blue-600 rounded" />
                              <span className={`text-[11px] leading-tight ${k.aiSuggestedNegative ? 'text-red-400' : 'text-gray-600'} font-medium`}>{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>

                <div className="w-full">
                  <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                    <div className="px-3 py-2 border-b flex justify-between items-center bg-gray-50/80">
                      <div className="flex items-center gap-2">
                        <Layers size={14} className="text-gray-400" />
                        <span className="text-[10px] font-black text-gray-500 uppercase tracking-wider">Основные результаты</span>
                      </div>
                      <span className="text-[10px] font-bold text-gray-400">{filteredKeywords('parsed').filter(k => !k.groupId).length} слов</span>
                    </div>

                    <div className="p-2 flex flex-col gap-1">
                       {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                        <label key={k.id} className={`flex items-center py-1.5 px-3 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'bg-blue-50 border-blue-200 shadow-xs' : 'bg-white border-gray-100 hover:border-gray-300 hover:shadow-xs'}`}>
                          <input 
                            type="checkbox" 
                            checked={selection.has(k.id)}
                            onChange={() => toggleSelect(k.id)}
                            className="mr-3 h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className={`text-xs font-medium flex-1 ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 left-0 right-0 p-4 bg-white/95 backdrop-blur-md border-t border-gray-200 shadow-2xl flex items-center justify-center gap-4 z-40 animate-in slide-in-from-bottom-5">
                <div className="flex flex-col text-center px-2">
                  <span className="text-[9px] text-gray-400 uppercase font-black">Выбрано</span>
                  <span className="text-lg font-black text-blue-600 leading-none">{selection.size}</span>
                </div>

                <div className="h-8 w-px bg-gray-200" />

                <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-2 px-5 bg-red-600 text-white rounded-lg text-xs font-bold hover:bg-red-700 transition-all shadow-md uppercase">
                  <MinusSquare size={16} /> Минус
                </button>

                <div className="relative group">
                  <button className="flex items-center gap-2 py-2 px-5 bg-blue-600 text-white rounded-lg text-xs font-bold hover:bg-blue-700 transition-all shadow-md uppercase">
                    <Layers size={16} /> В группу <ChevronDown size={14} />
                  </button>
                  <div className="absolute bottom-full mb-2 left-0 w-56 bg-white border border-gray-200 rounded-lg shadow-xl hidden group-hover:block p-2 overflow-hidden animate-in zoom-in-95">
                    <div className="max-h-48 overflow-y-auto space-y-0.5">
                      {currentProject?.groups.map(g => (
                        <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-1.5 text-[11px] hover:bg-blue-50 rounded font-bold text-gray-600 transition-colors">
                          {g.name}
                        </button>
                      ))}
                    </div>
                    <div className="h-px bg-gray-100 my-1.5" />
                    <button onClick={createGroup} className="w-full text-center p-1.5 text-[10px] text-blue-600 font-black hover:bg-blue-50 rounded uppercase border border-dashed border-blue-200">
                      + Новая группа
                    </button>
                  </div>
                </div>

                <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-2 px-5 bg-gray-100 text-gray-700 rounded-lg text-xs font-bold hover:bg-gray-200 transition-all uppercase border border-gray-200">
                  <Trash2 size={16} /> Удалить
                </button>

                <button onClick={() => setSelection(new Set())} className="p-2 bg-gray-50 hover:bg-red-50 hover:text-red-500 rounded-lg text-gray-400 transition-all border border-gray-100">
                  <X size={18} />
                </button>
             </div>
          )}
        </div>
      </main>

      {/* Word Analysis Modal */}
      {showAnalysis && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-2xl h-[85vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
             <div className="p-6 border-b flex justify-between items-center bg-indigo-50">
                <div className="flex items-center gap-3">
                   <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-lg"><Scissors size={24} /></div>
                   <div>
                      <h2 className="text-xl font-black text-indigo-900 leading-tight">Анализ по словам</h2>
                      <p className="text-[10px] text-indigo-400 uppercase font-black tracking-widest">Разбивка фраз на части</p>
                   </div>
                </div>
                <button onClick={() => setShowAnalysis(false)} className="p-2 hover:bg-indigo-100 rounded-full transition-colors"><X size={24} /></button>
             </div>

             <div className="flex-1 overflow-y-auto p-4 space-y-2 bg-gray-50/50">
                {wordAnalysisMap.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-4">
                    <Search size={48} />
                    <p className="text-sm font-bold uppercase tracking-widest">Нет данных для анализа</p>
                  </div>
                ) : (
                  wordAnalysisMap.map(([word, ids]) => {
                    const isExpanded = expandedWords.has(word);
                    const allInSelection = ids.every(id => selection.has(id));
                    const someInSelection = ids.some(id => selection.has(id));

                    return (
                      <div key={word} className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden transition-all">
                        <div className="flex items-center p-3 hover:bg-gray-50 transition-colors">
                          <input 
                            type="checkbox" 
                            checked={allInSelection}
                            ref={el => el && (el.indeterminate = someInSelection && !allInSelection)}
                            onChange={() => toggleWordSelection(word, ids)}
                            className="mr-4 h-5 w-5 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
                          />
                          <div className="flex-1 flex items-center justify-between cursor-pointer" onClick={() => toggleWordExpand(word)}>
                            <div className="flex flex-col">
                              <span className="text-sm font-black text-slate-700 capitalize">{word}</span>
                              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{ids.length} вхождений</span>
                            </div>
                            <div className="flex items-center gap-3">
                              {isExpanded ? <ChevronDown size={18} className="text-slate-400" /> : <ChevronRight size={18} className="text-slate-400" />}
                            </div>
                          </div>
                        </div>

                        {isExpanded && (
                          <div className="px-12 py-3 bg-gray-50/80 border-t border-gray-100 space-y-1.5">
                            {ids.map(id => {
                              const k = currentProject?.keywords.find(item => item.id === id);
                              if (!k) return null;
                              return (
                                <label key={id} className="flex items-center gap-3 group cursor-pointer">
                                  <input 
                                    type="checkbox" 
                                    checked={selection.has(id)} 
                                    onChange={() => toggleSelect(id)} 
                                    className="h-4 w-4 text-indigo-500 rounded border-gray-300" 
                                  />
                                  <span className="text-[11px] font-medium text-slate-500 group-hover:text-indigo-600 transition-colors">{k.text}</span>
                                </label>
                              );
                            })}
                          </div>
                        )}
                      </div>
                    );
                  })
                )}
             </div>

             {selection.size > 0 && (
               <div className="p-6 bg-white border-t border-gray-100 flex items-center justify-between gap-4">
                  <div className="flex flex-col">
                    <span className="text-[10px] text-slate-400 uppercase font-black">Выбрано запросов</span>
                    <span className="text-xl font-black text-indigo-600 leading-none">{selection.size}</span>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => moveKeywords('negative')} className="flex items-center gap-2 py-3 px-6 bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg shadow-red-200 hover:bg-red-700 transition-all">
                      <MinusSquare size={16} /> В минус
                    </button>
                    <button onClick={() => moveKeywords('trash')} className="flex items-center gap-2 py-3 px-6 bg-slate-900 text-white rounded-xl text-xs font-black uppercase tracking-widest shadow-lg shadow-slate-200 hover:bg-black transition-all">
                      <Trash2 size={16} /> Удалить
                    </button>
                  </div>
               </div>
             )}
          </div>
        </div>
      )}

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
              <div className="p-5 border-b flex justify-between items-center bg-blue-50">
                 <div className="flex items-center gap-3">
                    <div className="p-2 bg-blue-600 text-white rounded-lg"><Upload size={20} /></div>
                    <div>
                       <h2 className="text-lg font-bold text-blue-900 leading-tight">Загрузка слов</h2>
                       <p className="text-[10px] text-blue-400 uppercase font-bold">Список или текстовый файл</p>
                    </div>
                 </div>
                 <button onClick={() => setShowBulkAdd(false)} className="p-1.5 hover:bg-blue-100 rounded-full transition-colors"><X size={20} /></button>
              </div>
              <div className="p-6 space-y-5">
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full py-4 bg-white border-2 border-dashed border-gray-200 rounded-xl flex items-center justify-center gap-3 hover:border-blue-400 hover:bg-blue-50 transition-all"
                  >
                    <FileText size={24} className="text-gray-400" />
                    <span className="text-sm font-bold text-gray-600">Выбрать .txt файл</span>
                    <input type="file" ref={fileInputRef} className="hidden" accept=".txt,.csv" onChange={handleFileUpload} />
                 </button>

                 <div className="relative">
                   <textarea 
                     value={bulkInput}
                     onChange={(e) => setBulkInput(e.target.value)}
                     placeholder="Вставьте слова по одному на строку..."
                     className="w-full h-48 p-3 border border-gray-200 rounded-xl focus:ring-1 focus:ring-blue-500 outline-none font-mono text-xs resize-none bg-gray-50/50"
                   />
                 </div>

                 <button 
                    onClick={handleBulkAddAction}
                    disabled={!bulkInput.trim()}
                    className="w-full py-3.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-200 text-white rounded-xl font-black text-sm transition-all shadow-lg uppercase tracking-wider"
                 >
                    Загрузить в проект
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Project Manager Modal */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-sm shadow-2xl overflow-hidden">
            <div className="p-5 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-base font-bold text-gray-800 uppercase tracking-tight">Ваши Проекты</h2>
              <button onClick={() => { setShowProjectManager(false); setProjectToDeleteId(null); }} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="p-3 max-h-[50vh] overflow-y-auto space-y-2">
              {projects.map(p => (
                <div 
                  key={p.id} 
                  className={`relative flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${currentProjectId === p.id ? 'border-blue-400 bg-blue-50' : 'border-gray-100 hover:border-blue-200 hover:bg-gray-50'}`}
                  onClick={() => { if (!projectToDeleteId) { setCurrentProjectId(p.id); setShowProjectManager(false); } }}
                >
                  <div className="flex-1 pr-4">
                    <h3 className="text-sm font-bold text-gray-800 truncate">{p.name}</h3>
                    <p className="text-[10px] text-blue-600 font-bold uppercase mt-0.5">{p.keywords.length} слов</p>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); setProjectToDeleteId(p.id); }} className="p-1.5 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
            <div className="p-4 bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold flex items-center justify-center gap-2 uppercase tracking-wide transition-all"><Plus size={16} /> Создать проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Selected for Analysis Modal - Seeds */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[75vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-blue-50/40">
              <h2 className="text-xs font-black uppercase tracking-widest text-blue-900">Семантические семена</h2>
              <button onClick={() => { setShowSelected(false); setSelection(new Set()); }} className="p-1 hover:bg-blue-100 rounded-full transition-colors"><X size={18} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-2 bg-white space-y-0.5">
                 {currentProject?.keywords.filter(k => k.status === 'selected').length === 0 ? (
                   <div className="flex flex-col items-center justify-center py-20 text-gray-400 italic text-[11px]">
                     Нет выбранных слов для семян
                   </div>
                 ) : (
                   currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                     <label key={k.id} className={`flex items-center gap-2.5 px-3 py-1.5 rounded-md border transition-all cursor-pointer ${selection.has(k.id) ? 'border-blue-200 bg-blue-50' : 'border-gray-50 hover:border-gray-200 hover:bg-gray-50'}`}>
                       <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-3.5 w-3.5 text-blue-600 rounded" />
                       <span className="text-xs font-medium text-gray-700">{k.text}</span>
                     </label>
                   ))
                 )}
            </div>

            <div className="p-4 bg-gray-50 border-t space-y-2">
               <button 
                  onClick={startAnalysis}
                  disabled={loading || currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length === 0}
                  className="w-full py-3 bg-green-600 hover:bg-green-500 disabled:bg-gray-300 text-white rounded-lg font-black text-xs flex items-center justify-center gap-2.5 transition-all uppercase tracking-widest shadow-md"
                >
                  {loading ? <Loader2 className="animate-spin" size={16} /> : <Play size={16} fill="currentColor" />}
                  Запустить расширение ({currentProject?.keywords.filter(k => k.status === 'selected' && selection.has(k.id)).length})
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList, Scissors
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Analysis state
  const [expandedWords, setExpandedWords] = useState<Set<string>>(new Set());

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map(i => parsedKeywords[i].id));

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  // Word Analysis Logic - Compact & Accurate
  const wordAnalysisMap = useMemo(() => {
    const map: Record<string, string[]> = {};
    const parsed = filteredKeywords('parsed');

    parsed.forEach(k => {
      const words = k.text.toLowerCase().split(/[^a-zа-я0-9]/).filter(w => w.length > 1);
      const uniqueInPhrase = [...new Set(words)];
      uniqueInPhrase.forEach(w => {
        if (!map[w]) map[w] = [];
        map[w].push(k.id);
      });
    });

    return Object.entries(map).sort((a, b) => b[1].length - a[1].length);
  }, [currentProject?.keywords, searchQuery, filteredKeywords]);

  const toggleWordSelection = (ids: string[]) => {
    const next = new Set(selection);
    const allSelected = ids.every(id => next.has(id));

    if (allSelected) {
      ids.forEach(id => next.delete(id));
    } else {
      ids.forEach(id => next.add(id));
    }
    setSelection(next);
  };

  const toggleWordExpand = (word: string) => {
    const next = new Set(expandedWords);
    if (next.has(word)) next.delete(word);
    else next.add(word);
    setExpandedWords(next);
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">
        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-3 border-b border-gray-100 space-y-3">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-[10px] tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-[10px] text-red-500 hover:underline flex items-center gap-1 font-bold">
                <MinusSquare size={10} /> Минус-слова
              </button>
            </div>
            <div className="flex gap-1.5">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-2.5 pr-2.5 py-1.5 border border-gray-200 rounded text-xs focus:ring-1 focus:ring-blue-500 outline-none"
                />
              </div>
              <button onClick={triggerSuggestions} disabled={loading || !themeInput.trim()} className="p-1.5 rounded border bg-blue-600 text-white hover:bg-blue-500">
                {loading ? <Loader2 className="animate-spin" size={14} /> : <Search size={14} />}
              </button>
            </div>
            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1 text-[10px] bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-black uppercase">
              Отобранные ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>
          <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5 bg-gray-50/50">
            {filteredKeywords('preliminary').map(k => (
              <div key={k.id} className="flex items-center p-1 rounded hover:bg-white transition-all">
                <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 rounded text-blue-600" />
                <span className="text-[11px] text-gray-600 flex-1 truncate">{k.text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3">
              <button onClick={runSmartFilter} className="px-3 py-1.5 bg-indigo-600 text-white rounded text-xs font-bold">Умный отбор</button>
              <button onClick={() => setShowBulkAdd(true)} className="px-3 py-1.5 bg-blue-600 text-white rounded text-xs font-bold">Добавить список</button>
              <input type="text" placeholder="Поиск..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-56 px-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs outline-none" />
            </div>
            <button onClick={createGroup} className="px-3 py-1.5 border border-gray-200 rounded text-xs font-bold">Группа</button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {currentProject && (
              <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    return (
                      <div key={group.id} className="bg-white rounded border border-gray-200 flex flex-col max-h-60">
                        <div className="p-2 border-b bg-blue-50/40 font-bold text-[10px] uppercase">{group.name}</div>
                        <div className="overflow-y-auto p-1.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className="flex items-center p-1 hover:bg-gray-50 cursor-pointer">
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 rounded" />
                              <span className="text-[10px] truncate">{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
                <div className="bg-white rounded border border-gray-200 overflow-hidden">
                  <div className="px-3 py-1.5 bg-gray-50 text-[10px] font-black uppercase tracking-wider border-b">Основные результаты</div>
                  <div className="p-2 flex flex-col">
                    {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                      <label key={k.id} className="flex items-center py-1 px-2 hover:bg-gray-50 cursor-pointer rounded">
                        <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-3 h-3.5 w-3.5 rounded" />
                        <span className={`text-[11px] font-medium ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && (
             <div className="sticky bottom-0 p-4 bg-white border-t border-gray-200 shadow-xl flex items-center justify-center gap-4 z-40">
                <div className="text-center px-2">
                  <span className="text-[10px] text-gray-400 font-black">ВЫБРАНО: {selection.size}</span>
                </div>
                <button onClick={() => moveKeywords('negative')} className="px-5 py-2 bg-red-600 text-white rounded text-[10px] font-black uppercase">В минус</button>
                <button onClick={() => moveKeywords('trash')} className="px-5 py-2 bg-slate-800 text-white rounded text-[10px] font-black uppercase">Удалить</button>
                <button onClick={() => setSelection(new Set())} className="p-2 text-gray-400"><X size={18} /></button>
             </div>
          )}
        </div>
      </main>

      {/* Word Analysis Modal - ULTRA COMPACT */}
      {showAnalysis && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
             <div className="p-4 border-b flex justify-between items-center bg-indigo-50/50">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-indigo-600 text-white rounded-lg"><Scissors size={18} /></div>
                   <div>
                      <h2 className="text-sm font-black text-indigo-900 leading-tight uppercase">Анализ по словам</h2>
                      <p className="text-[9px] text-indigo-400 uppercase font-bold tracking-widest">Разбивка фраз на части</p>
                   </div>
                </div>
                <button onClick={() => setShowAnalysis(false)} className="p-1.5 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-full transition-colors"><X size={20} /></button>
             </div>

             <div className="flex-1 overflow-y-auto p-3 space-y-1 bg-gray-50/30">
                {wordAnalysisMap.map(([word, ids]) => {
                  const isExpanded = expandedWords.has(word);
                  const allInSelection = ids.every(id => selection.has(id));
                  const someInSelection = ids.some(id => selection.has(id));

                  return (
                    <div key={word} className="bg-white rounded border border-gray-200 transition-all">
                      <div className="flex items-center p-2 hover:bg-gray-50 group">
                        <input 
                          type="checkbox" 
                          checked={allInSelection}
                          ref={el => el && (el.indeterminate = someInSelection && !allInSelection)}
                          onChange={() => toggleWordSelection(ids)}
                          className="mx-2 h-4 w-4 rounded border-gray-300 text-indigo-600 cursor-pointer"
                        />
                        <div className="flex-1 flex items-center justify-between cursor-pointer py-1" onClick={() => toggleWordExpand(word)}>
                          <div className="flex flex-col">
                            <span className="text-xs font-bold text-slate-700 capitalize">{word}</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{ids.length} вхождений</span>
                          </div>
                          {isExpanded ? <ChevronDown size={14} className="text-slate-400" /> : <ChevronRight size={14} className="text-slate-400" />}
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-10 py-2 bg-gray-50/80 border-t border-gray-100 space-y-0.5">
                          {ids.map(id => {
                            const k = currentProject?.keywords.find(item => item.id === id);
                            if (!k) return null;
                            return (
                              <label key={id} className="flex items-center gap-2 py-0.5 group cursor-pointer">
                                <input 
                                  type="checkbox" 
                                  checked={selection.has(id)} 
                                  onChange={() => toggleSelect(id)} 
                                  className="h-3 w-3 text-indigo-500 rounded border-gray-300" 
                                />
                                <span className="text-[10px] text-slate-500 truncate group-hover:text-indigo-600">{k.text}</span>
                              </label>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
             </div>

             <div className="p-4 bg-white border-t flex items-center justify-between">
                <div className="flex flex-col">
                  <span className="text-[9px] text-slate-400 uppercase font-black">ВЫБРАНО ЗАПРОСОВ</span>
                  <span className="text-lg font-black text-indigo-600 leading-none">{selection.size}</span>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => moveKeywords('negative')} className="px-6 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-wider shadow-lg shadow-red-100">В минус</button>
