import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList, Scissors
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Analysis state
  const [expandedWords, setExpandedWords] = useState<Set<string>>(new Set());

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      // Fix: Ensure negativeIndices are treated as numbers for indexing to prevent unknown type errors
      const negativeIds = new Set(negativeIndices.map((i: number) => parsedKeywords[i]?.id).filter(Boolean) as string[]);

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status: 'parsed', groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  // Word Analysis Logic - Compact & Accurate
  const wordAnalysisMap = useMemo((): [string, string[]][] => {
    const map: Record<string, string[]> = {};
    const parsed = filteredKeywords('parsed');

    // Fix: Added explicit type annotation (k: Keyword) and used Array.from to prevent "unknown" type inference errors
    parsed.forEach((k: Keyword) => {
      const words = k.text.toLowerCase().split(/[^a-zа-я0-9]/).filter(w => w.length > 1);
      // Fix: Use Array.from for Set iteration to ensure correctly typed array of strings
      const uniqueInPhrase = Array.from(new Set(words));
      uniqueInPhrase.forEach((w: string) => {
        if (!map[w]) map[w] = [];
        map[w].push(k.id);
      });
    });

    return Object.entries(map).sort((a, b) => b[1].length - a[1].length);
  }, [currentProject?.keywords, searchQuery, filteredKeywords]);

  const toggleWordSelection = (ids: string[]) => {
    const next = new Set(selection);
    const allSelected = ids.every(id => next.has(id));

    if (allSelected) {
      ids.forEach(id => next.delete(id));
    } else {
      ids.forEach(id => next.add(id));
    }
    setSelection(next);
  };

  const toggleWordExpand = (word: string) => {
    const next = new Set(expandedWords);
    if (next.has(word)) next.delete(word);
    else next.add(word);
    setExpandedWords(next);
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">
        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-3 border-b border-gray-100 space-y-3">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-[10px] tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-[10px] text-red-500 hover:underline flex items-center gap-1 font-bold">
                <MinusSquare size={10} /> Минус-слова
              </button>
            </div>
            <div className="flex gap-1.5">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-2.5 pr-2.5 py-1.5 border border-gray-200 rounded text-xs focus:ring-1 focus:ring-blue-500 outline-none"
                />
              </div>
              <button onClick={triggerSuggestions} disabled={loading || !themeInput.trim()} className="p-1.5 rounded border bg-blue-600 text-white hover:bg-blue-500">
                {loading ? <Loader2 className="animate-spin" size={14} /> : <Search size={14} />}
              </button>
            </div>
            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1 text-[10px] bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-black uppercase">
              Отобранные ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>
          <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5 bg-gray-50/50">
            {filteredKeywords('preliminary').map(k => (
              <div key={k.id} className="flex items-center p-1 rounded hover:bg-white transition-all">
                <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 rounded text-blue-600" />
                <span className="text-[11px] text-gray-600 flex-1 truncate">{k.text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3">
              <button onClick={runSmartFilter} className="px-3 py-1.5 bg-indigo-600 text-white rounded text-xs font-bold">Умный отбор</button>
              <button onClick={() => setShowBulkAdd(true)} className="px-3 py-1.5 bg-blue-600 text-white rounded text-xs font-bold">Добавить список</button>
              <input type="text" placeholder="Поиск..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-56 px-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs outline-none" />
            </div>
            <button onClick={createGroup} className="px-3 py-1.5 border border-gray-200 rounded text-xs font-bold">Группа</button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {currentProject && (
              <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    return (
                      <div key={group.id} className="bg-white rounded border border-gray-200 flex flex-col max-h-60">
                        <div className="p-2 border-b bg-blue-50/40 font-bold text-[10px] uppercase">{group.name}</div>
                        <div className="overflow-y-auto p-1.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className="flex items-center p-1 hover:bg-gray-50 cursor-pointer">
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 rounded" />
                              <span className="text-[10px] truncate">{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
                <div className="bg-white rounded border border-gray-200 overflow-hidden">
                  <div className="px-3 py-1.5 bg-gray-50 text-[10px] font-black uppercase tracking-wider border-b">Основные результаты</div>
                  <div className="p-2 flex flex-col">
                    {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                      <label key={k.id} className="flex items-center py-1 px-2 hover:bg-gray-50 cursor-pointer rounded">
                        <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-3 h-3.5 w-3.5 rounded" />
                        <span className={`text-[11px] font-medium ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && (
             <div className="sticky bottom-0 p-4 bg-white border-t border-gray-200 shadow-xl flex items-center justify-center gap-4 z-40">
                <div className="text-center px-2">
                  <span className="text-[10px] text-gray-400 font-black">ВЫБРАНО: {selection.size}</span>
                </div>
                <button onClick={() => moveKeywords('negative')} className="px-5 py-2 bg-red-600 text-white rounded text-[10px] font-black uppercase">В минус</button>
                <button onClick={() => moveKeywords('trash')} className="px-5 py-2 bg-slate-800 text-white rounded text-[10px] font-black uppercase">Удалить</button>
                <button onClick={() => setSelection(new Set())} className="p-2 text-gray-400"><X size={18} /></button>
             </div>
          )}
        </div>
      </main>

      {/* Word Analysis Modal - ULTRA COMPACT */}
      {showAnalysis && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
             <div className="p-4 border-b flex justify-between items-center bg-indigo-50/50">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-indigo-600 text-white rounded-lg"><Scissors size={18} /></div>
                   <div>
                      <h2 className="text-sm font-black text-indigo-900 leading-tight uppercase">Анализ по словам</h2>
                      <p className="text-[9px] text-indigo-400 uppercase font-bold tracking-widest">Разбивка фраз на части</p>
                   </div>
                </div>
                <button onClick={() => setShowAnalysis(false)} className="p-1.5 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-full transition-colors"><X size={20} /></button>
             </div>

             <div className="flex-1 overflow-y-auto p-3 space-y-1 bg-gray-50/30">
                {wordAnalysisMap.map(([word, ids]) => {
                  const isExpanded = expandedWords.has(word);
                  const allInSelection = ids.every(id => selection.has(id));
                  const someInSelection = ids.some(id => selection.has(id));

                  return (
                    <div key={word} className="bg-white rounded border border-gray-200 transition-all">
                      <div className="flex items-center p-2 hover:bg-gray-50 group">
                        <input 
                          type="checkbox" 
                          checked={allInSelection}
                          ref={el => el && (el.indeterminate = someInSelection && !allInSelection)}
                          onChange={() => toggleWordSelection(ids)}
                          className="mx-2 h-4 w-4 rounded border-gray-300 text-indigo-600 cursor-pointer"
                        />
                        <div className="flex-1 flex items-center justify-between cursor-pointer py-1" onClick={() => toggleWordExpand(word)}>
                          <div className="flex flex-col">
                            <span className="text-xs font-bold text-slate-700 capitalize">{word}</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{ids.length} вхождений</span>
                          </div>
                          {isExpanded ? <ChevronDown size={14} className="text-slate-400" /> : <ChevronRight size={14} className="text-slate-400" />}
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-10 py-2 bg-gray-50/80 border-t border-gray-100 space-y-0.5">
                          {ids.map(id => {
                            const k = currentProject?.keywords.find(item => item.id === id);
                            if (!k) return null;
                            return (
                              <label key={id} className="flex items-center gap-2 py-0.5 group cursor-pointer">
                                <input 
                                  type="checkbox" 
                                  checked={selection.has(id)} 
                                  onChange={() => toggleSelect(id)} 
                                  className="h-3 w-3 text-indigo-500 rounded border-gray-300" 
                                />
                                <span className="text-[10px] text-slate-500 truncate group-hover:text-indigo-600">{k.text}</span>
                              </label>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
             </div>

             <div className="p-4 bg-white border-t flex items-center justify-between">
                <div className="flex flex-col">
                  <span className="text-[9px] text-slate-400 uppercase font-black">ВЫБРАНО ЗАПРОСОВ</span>
                  <span className="text-lg font-black text-indigo-600 leading-none">{selection.size}</span>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => moveKeywords('negative')} className="px-6 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-wider shadow-lg shadow-red-100">В минус</button>
                  <button onClick={() => moveKeywords('trash')} className="px-6 py-2 bg-slate-900 text-white rounded-lg text-[10px] font-black uppercase tracking-wider">Удалить</button>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Trash Modal */}
      {showTrash && (
        <div className="fixed inset-0 bg-black/60 z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[60vh] flex flex-col shadow-2xl">
            <div className="p-4 border-b flex justify-between items-center">
              <h2 className="text-sm font-black uppercase">Корзина ({currentProject?.keywords.filter(k => k.status === 'trash').length})</h2>
              <button onClick={() => setShowTrash(false)}><X size={20}/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-1">
               {currentProject?.keywords.filter(k => k.status === 'trash').map(k => (
                 <div key={k.id} className="text-[10px] p-2 bg-gray-50 rounded flex justify-between">
                   <span>{k.text}</span>
                   <button onClick={() => {
                     updateProject(p => ({
                       ...p,
                       keywords: p.keywords.map(kw => kw.id === k.id ? { ...kw, status: 'parsed' } : kw)
                     }))
                   }} className="text-blue-600 font-bold hover:underline">Вернуть</button>
                 </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-md p-6 flex flex-col shadow-2xl">
              <h2 className="text-lg font-bold mb-4">Массовая загрузка</h2>
              <textarea value={bulkInput} onChange={(e) => setBulkInput(e.target.value)} placeholder="По одному слову на строку..." className="w-full h-48 p-3 border rounded text-xs mb-4 outline-none font-mono" />
              <button onClick={handleBulkAddAction} className="w-full py-3 bg-blue-600 text-white rounded font-bold uppercase text-xs">Загрузить</button>
              <button onClick={() => setShowBulkAdd(false)} className="mt-2 text-xs text-gray-400 text-center hover:underline">Отмена</button>
           </div>
        </div>
      )}

      {/* Project Manager */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-sm overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-xs font-black uppercase">Проекты</h2>
              <button onClick={() => setShowProjectManager(false)}><X size={18}/></button>
            </div>
            <div className="p-2 max-h-60 overflow-y-auto space-y-1">
              {projects.map(p => (
                <div key={p.id} onClick={() => { setCurrentProjectId(p.id); setShowProjectManager(false); }} className={`p-3 rounded text-xs font-bold cursor-pointer transition-all ${currentProjectId === p.id ? 'bg-blue-50 border-blue-200 border' : 'hover:bg-gray-100 border-transparent border'}`}>
                  {p.name} <span className="text-[9px] text-blue-400 ml-2">({p.keywords.length})</span>
                </div>
              ))}
            </div>
            <div className="p-4 border-t bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-2 bg-blue-600 text-white rounded text-xs font-bold uppercase">+ Создать проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Seeds Modal */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[70vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-blue-50/40 font-black text-xs uppercase">Семена для анализа</div>
            <div className="flex-1 overflow-y-auto p-2">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className="flex items-center p-2 hover:bg-gray-50 rounded">
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-4 w-4 mr-3" />
                     <span className="text-xs font-bold">{k.text}</span>
                   </label>
                 ))}
            </div>
            <div className="p-4 border-t bg-gray-50">
               <button onClick={startAnalysis} disabled={loading || selection.size === 0} className="w-full py-3 bg-green-600 text-white rounded font-black text-xs uppercase flex items-center justify-center gap-2">
                  <Play size={14} fill="currentColor" /> Запустить расширение
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { 
  Plus, Search, Trash2, ArrowRight, MinusSquare, CheckSquare, 
  Play, Filter, Layers, BrainCircuit, RotateCcw, X, ChevronDown, ChevronRight,
  Save, FolderOpen, MoreHorizontal, Download, Sparkles, Loader2, List, AlertTriangle,
  SortAsc, SortDesc, Upload, FileText, ClipboardList, Scissors, Undo2, FolderPlus
} from 'lucide-react';
import { Keyword, Project, Group, KeywordStatus } from './types';
import { fetchSynonymsAndSuggestions, expandKeywords, smartFilterKeywords } from './geminiService';

const STORAGE_KEY = 'keyword_pro_projects_v2';

const App: React.FC = () => {
  // State
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [themeInput, setThemeInput] = useState('');
  const [selection, setSelection] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc' | null>(null);

  // Modals state
  const [showNegatives, setShowNegatives] = useState(false);
  const [showSelected, setShowSelected] = useState(false);
  const [showTrash, setShowTrash] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [showProjectManager, setShowProjectManager] = useState(false);
  const [showBulkAdd, setShowBulkAdd] = useState(false);

  // Analysis state
  const [expandedWords, setExpandedWords] = useState<Set<string>>(new Set());

  // Bulk add state
  const [bulkInput, setBulkInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Project deletion confirmation state
  const [projectToDeleteId, setProjectToDeleteId] = useState<string | null>(null);

  // Derived state
  const currentProject = useMemo(() => 
    projects.find(p => p.id === currentProjectId) || null
  , [projects, currentProjectId]);

  useEffect(() => {
    if (currentProject) {
      setThemeInput(currentProject.theme || '');
    } else {
      setThemeInput('');
    }
    setSelection(new Set());
  }, [currentProjectId]);

  // Persistence
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setProjects(parsed);
        if (parsed.length > 0) setCurrentProjectId(parsed[0].id);
      } catch (e) {
        console.error("Failed to load projects", e);
      }
    }
  }, []);

  useEffect(() => {
    if (projects.length >= 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }, [projects]);

  // Actions
  const createProject = (name?: string, theme?: string) => {
    const projectName = name || prompt("Назовите ваш проект:");
    if (!projectName) return null;
    const newId = Math.random().toString(36).substr(2, 9);
    const newProject: Project = {
      id: newId,
      name: projectName,
      theme: theme || '',
      keywords: [],
      groups: [],
      createdAt: Date.now(),
    };
    setProjects(prev => [...prev, newProject]);
    setCurrentProjectId(newId);
    setShowProjectManager(false);
    return newId;
  };

  const updateProject = (updater: (p: Project) => Project) => {
    if (!currentProjectId) return;
    setProjects(prev => prev.map(p => p.id === currentProjectId ? updater(p) : p));
  };

  const handleThemeChange = (val: string) => {
    setThemeInput(val);
    if (currentProjectId) {
      updateProject(p => ({ ...p, theme: val }));
    }
  };

  const addKeywordsToProject = (rawTexts: string[], status: KeywordStatus = 'parsed') => {
    if (!currentProject) return 0;

    const existingTexts = new Set(currentProject.keywords.map(k => k.text.trim().toLowerCase()));
    const uniqueNewKeywords: Keyword[] = [];

    rawTexts.forEach(text => {
      const cleaned = text.trim();
      if (cleaned && !existingTexts.has(cleaned.toLowerCase())) {
        uniqueNewKeywords.push({
          id: Math.random().toString(36).substr(2, 9),
          text: cleaned,
          status: status
        });
        existingTexts.add(cleaned.toLowerCase());
      }
    });

    if (uniqueNewKeywords.length > 0) {
      updateProject(p => ({
        ...p,
        keywords: [...p.keywords, ...uniqueNewKeywords]
      }));
    }
    return uniqueNewKeywords.length;
  };

  const triggerSuggestions = async () => {
    const input = themeInput.trim();
    if (!input) {
      alert("Введите тематику бизнеса");
      return;
    }

    let activeProjectId = currentProjectId;
    if (!activeProjectId) {
      activeProjectId = createProject(`Проект: ${input}`, input);
      if (!activeProjectId) return;
    }

    setLoading(true);
    try {
      const suggestions = await fetchSynonymsAndSuggestions(input);
      addKeywordsToProject(suggestions, 'preliminary');
    } finally {
      setLoading(false);
    }
  };

  const handleBulkAddAction = () => {
    const lines = bulkInput.split(/[\n,;]/).map(l => l.trim()).filter(l => l.length > 0);
    if (lines.length === 0) return;

    const addedCount = addKeywordsToProject(lines);
    alert(`Добавлено новых слов: ${addedCount}. Точные дубликаты пропущены.`);
    setBulkInput('');
    setShowBulkAdd(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setBulkInput(prev => (prev ? prev + '\n' + content : content));
    };
    reader.readAsText(file);
  };

  const toggleSelect = (id: string) => {
    const next = new Set(selection);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelection(next);
  };

  const moveKeywords = (status: KeywordStatus) => {
    if (selection.size === 0) return;
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, status, groupId: status === 'negative' ? k.groupId : undefined } : k)
    }));
    setSelection(new Set());
  };

  const startAnalysis = async () => {
    if (!currentProject) return;

    const seeds = currentProject.keywords
      .filter(k => k.status === 'selected' && selection.has(k.id))
      .map(k => k.text);

    if (seeds.length === 0) {
      alert("Выберите хотя бы одно слово из списка галочками для начала сбора запросов");
      return;
    }

    setLoading(true);
    try {
      const expanded = await expandKeywords(seeds, currentProject.theme);
      addKeywordsToProject(expanded, 'parsed');
      setShowSelected(false);
      setSelection(new Set());
    } finally {
      setLoading(false);
    }
  };

  const runSmartFilter = async () => {
    if (!currentProject) return;
    const parsedKeywords = currentProject.keywords.filter(k => k.status === 'parsed');
    if (parsedKeywords.length === 0) return;

    setLoading(true);
    try {
      const texts = parsedKeywords.map(k => k.text);
      const chunk = texts.slice(0, 50); 
      const negativeIndices = await smartFilterKeywords(chunk, currentProject.theme);
      const negativeIds = new Set(negativeIndices.map((i: number) => parsedKeywords[i]?.id).filter(Boolean) as string[]);

      const nextSelection = new Set(selection);
      negativeIds.forEach(id => nextSelection.add(id));
      setSelection(nextSelection);

      updateProject(p => ({
        ...p,
        keywords: p.keywords.map(k => negativeIds.has(k.id) ? { ...k, aiSuggestedNegative: true } : k)
      }));
    } finally {
      setLoading(false);
    }
  };

  const createGroup = () => {
    const name = prompt("Название группы:");
    if (!name) return;
    const newGroup: Group = { id: Math.random().toString(36).substr(2, 9), name };
    updateProject(p => ({ ...p, groups: [...p.groups, newGroup] }));
  };

  const moveToGroup = (groupId: string) => {
    updateProject(p => ({
      ...p,
      keywords: p.keywords.map(k => selection.has(k.id) ? { ...k, groupId } : k)
    }));
    setSelection(new Set());
  };

  const filteredKeywords = useCallback((status: KeywordStatus) => {
    if (!currentProject) return [];
    let items = currentProject.keywords.filter(k => k.status === status && k.text.toLowerCase().includes(searchQuery.toLowerCase()));

    if (status === 'parsed') {
      if (sortOrder === 'asc') items = [...items].sort((a, b) => a.text.localeCompare(b.text));
      else if (sortOrder === 'desc') items = [...items].sort((a, b) => b.text.localeCompare(a.text));
    }

    return items;
  }, [currentProject, searchQuery, sortOrder]);

  const wordAnalysisMap = useMemo((): [string, string[]][] => {
    const map: Record<string, string[]> = {};
    const parsed = filteredKeywords('parsed');

    parsed.forEach((k: Keyword) => {
      const words = k.text.toLowerCase().split(/[^a-zа-я0-9]/).filter(w => w.length > 1);
      const uniqueInPhrase = Array.from(new Set(words));
      uniqueInPhrase.forEach((w: string) => {
        if (!map[w]) map[w] = [];
        map[w].push(k.id);
      });
    });

    return Object.entries(map).sort((a, b) => b[1].length - a[1].length);
  }, [currentProject?.keywords, searchQuery, filteredKeywords]);

  const toggleWordSelection = (ids: string[]) => {
    const next = new Set(selection);
    const allSelected = ids.every(id => next.has(id));

    if (allSelected) {
      ids.forEach(id => next.delete(id));
    } else {
      ids.forEach(id => next.add(id));
    }
    setSelection(next);
  };

  const toggleWordExpand = (word: string) => {
    const next = new Set(expandedWords);
    if (next.has(word)) next.delete(word);
    else next.add(word);
    setExpandedWords(next);
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      {/* Top Header */}
      <header className="h-16 bg-slate-900 text-white flex items-center justify-between px-6 shadow-md z-30">
        <div className="flex items-center gap-4">
          <Layers className="text-blue-400" size={28} />
          <h1 className="text-xl font-bold tracking-tight">KeywordPro <span className="text-blue-400">AI</span></h1>
          <div className="h-6 w-px bg-slate-700 mx-2" />
          <button 
            onClick={() => setShowProjectManager(true)}
            className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 rounded-md hover:bg-slate-700 transition-colors text-sm"
          >
            <FolderOpen size={16} />
            {currentProject ? currentProject.name : 'Выбрать проект'}
          </button>
        </div>

        <div className="flex items-center gap-3">
          {loading && (
            <div className="flex items-center gap-2 text-xs text-blue-300 animate-pulse">
              <Loader2 className="animate-spin" size={14} />
              AI работает...
            </div>
          )}
          <button 
             onClick={() => setShowAnalysis(true)}
             className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded text-sm font-medium flex items-center gap-2 transition-all shadow-lg shadow-blue-900/20"
          >
            <Search size={16} /> Анализ слов
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <main className="flex-1 flex overflow-hidden bg-gray-100">
        {/* Left Panel: Preliminary Selection */}
        <div className="w-1/4 bg-white border-r border-gray-200 flex flex-col shadow-sm">
          <div className="p-3 border-b border-gray-100 space-y-3">
            <div className="flex justify-between items-center">
              <h2 className="font-bold text-gray-700 uppercase text-[10px] tracking-wider">Предварительный отбор</h2>
              <button onClick={() => setShowNegatives(true)} className="text-[10px] text-red-500 hover:underline flex items-center gap-1 font-bold">
                <MinusSquare size={10} /> Минус-слова
              </button>
            </div>
            <div className="flex gap-1.5">
              <div className="relative flex-1">
                <input 
                  type="text" 
                  placeholder="Тематика..."
                  value={themeInput}
                  onChange={(e) => handleThemeChange(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && triggerSuggestions()}
                  className="w-full pl-2.5 pr-2.5 py-1.5 border border-gray-200 rounded text-xs focus:ring-1 focus:ring-blue-500 outline-none"
                />
              </div>
              <button onClick={triggerSuggestions} disabled={loading || !themeInput.trim()} className="p-1.5 rounded border bg-blue-600 text-white hover:bg-blue-500">
                {loading ? <Loader2 className="animate-spin" size={14} /> : <Search size={14} />}
              </button>
            </div>
            <button onClick={() => { setShowSelected(true); setSelection(new Set()); }} className="w-full py-1 text-[10px] bg-slate-100 rounded border hover:bg-slate-200 text-gray-600 font-black uppercase">
              Отобранные ({currentProject?.keywords.filter(k => k.status === 'selected').length || 0})
            </button>
          </div>
          <div className="flex-1 overflow-y-auto p-1.5 space-y-0.5 bg-gray-50/50">
            {filteredKeywords('preliminary').map(k => (
              <div key={k.id} className="flex items-center p-1 rounded hover:bg-white transition-all">
                <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 rounded text-blue-600" />
                <span className="text-[11px] text-gray-600 flex-1 truncate">{k.text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Right Panel: Main Keyword List */}
        <div className="flex-1 flex flex-col">
          <div className="p-3 bg-white border-b border-gray-200 flex items-center justify-between shadow-sm">
            <div className="flex items-center gap-3">
              <button onClick={runSmartFilter} className="px-3 py-1.5 bg-indigo-600 text-white rounded text-xs font-bold">Умный отбор</button>
              <button onClick={() => setShowBulkAdd(true)} className="px-3 py-1.5 bg-blue-600 text-white rounded text-xs font-bold">Добавить список</button>
              <input type="text" placeholder="Поиск..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-56 px-3 py-1.5 bg-gray-50 border border-gray-200 rounded text-xs outline-none" />
            </div>
            <button onClick={createGroup} className="px-3 py-1.5 border border-gray-200 rounded text-xs font-bold">Группа</button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
            {currentProject && (
              <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {currentProject.groups.map(group => {
                    const groupKeywords = filteredKeywords('parsed').filter(k => k.groupId === group.id);
                    return (
                      <div key={group.id} className="bg-white rounded border border-gray-200 flex flex-col max-h-60">
                        <div className="p-2 border-b bg-blue-50/40 font-bold text-[10px] uppercase">{group.name}</div>
                        <div className="overflow-y-auto p-1.5">
                          {groupKeywords.map(k => (
                            <label key={k.id} className="flex items-center p-1 hover:bg-gray-50 cursor-pointer">
                              <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3 w-3 rounded" />
                              <span className="text-[10px] truncate">{k.text}</span>
                            </label>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
                <div className="bg-white rounded border border-gray-200 overflow-hidden">
                  <div className="px-3 py-1.5 bg-gray-50 text-[10px] font-black uppercase tracking-wider border-b">Основные результаты</div>
                  <div className="p-2 flex flex-col">
                    {filteredKeywords('parsed').filter(k => !k.groupId).map(k => (
                      <label key={k.id} className="flex items-center py-1 px-2 hover:bg-gray-50 cursor-pointer rounded">
                        <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-3 h-3.5 w-3.5 rounded" />
                        <span className={`text-[11px] font-medium ${k.aiSuggestedNegative ? 'text-red-500 line-through' : 'text-gray-700'}`}>{k.text}</span>
                      </label>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Sticky Actions */}
          {selection.size > 0 && Array.from(selection).some(id => currentProject?.keywords.find(k => k.id === id)?.status === 'parsed') && (
             <div className="sticky bottom-0 p-4 bg-white border-t border-gray-200 shadow-xl flex items-center justify-center gap-4 z-40">
                <div className="text-center px-2">
                  <span className="text-[10px] text-gray-400 font-black">ВЫБРАНО: {selection.size}</span>
                </div>
                <button onClick={() => moveKeywords('negative')} className="px-5 py-2 bg-red-600 text-white rounded text-[10px] font-black uppercase">В минус</button>
                <button onClick={() => moveKeywords('trash')} className="px-5 py-2 bg-slate-800 text-white rounded text-[10px] font-black uppercase">Удалить</button>
                <button onClick={() => setSelection(new Set())} className="p-2 text-gray-400"><X size={18} /></button>
             </div>
          )}
        </div>
      </main>

      {/* Negative Keywords Modal */}
      {showNegatives && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-2xl h-[85vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
             <div className="p-5 border-b flex justify-between items-center bg-red-50/50">
                <div className="flex items-center gap-3">
                   <div className="p-2.5 bg-red-600 text-white rounded-xl shadow-lg shadow-red-200"><MinusSquare size={20} /></div>
                   <div>
                      <h2 className="text-base font-black text-red-900 leading-tight uppercase">Минус-слова проекта</h2>
                      <p className="text-[9px] text-red-400 uppercase font-bold tracking-widest">Список исключаемых запросов</p>
                   </div>
                </div>
                <button onClick={() => { setShowNegatives(false); setSelection(new Set()); }} className="p-2 hover:bg-red-100 text-red-500 rounded-full transition-colors"><X size={24} /></button>
             </div>

             <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/30">
                {/* Categorized Negative Keywords */}
                {currentProject?.groups.map(group => {
                  const groupNegatives = currentProject.keywords.filter(k => k.status === 'negative' && k.groupId === group.id);
                  if (groupNegatives.length === 0) return null;
                  return (
                    <div key={group.id} className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
                      <div className="p-2 px-3 bg-red-50/30 border-b flex justify-between items-center">
                        <span className="text-[10px] font-black text-red-700 uppercase">{group.name}</span>
                        <span className="text-[9px] bg-white px-1.5 py-0.5 rounded border border-red-100 font-bold text-red-600">{groupNegatives.length}</span>
                      </div>
                      <div className="p-2 grid grid-cols-2 gap-1">
                        {groupNegatives.map(k => (
                          <label key={k.id} className={`flex items-center p-1.5 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'bg-red-50 border-red-200' : 'bg-white border-transparent hover:border-gray-100'}`}>
                            <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3.5 w-3.5 text-red-600 rounded" />
                            <span className="text-[11px] font-medium text-gray-700 truncate">{k.text}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  );
                })}

                {/* Uncategorized Negative Keywords */}
                <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
                   <div className="p-2 px-3 bg-gray-50 border-b text-[10px] font-black text-gray-500 uppercase tracking-widest">Общий список минус-слов</div>
                   <div className="p-2 grid grid-cols-2 gap-1">
                      {currentProject?.keywords.filter(k => k.status === 'negative' && !k.groupId).length === 0 ? (
                        <div className="col-span-2 py-4 text-center text-[10px] text-gray-400 font-bold uppercase tracking-wider">Нет слов в общем списке</div>
                      ) : (
                        currentProject?.keywords.filter(k => k.status === 'negative' && !k.groupId).map(k => (
                          <label key={k.id} className={`flex items-center p-1.5 rounded-lg border transition-all cursor-pointer ${selection.has(k.id) ? 'bg-red-50 border-red-200' : 'bg-white border-transparent hover:border-gray-100'}`}>
                            <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="mr-2 h-3.5 w-3.5 text-red-600 rounded" />
                            <span className="text-[11px] font-medium text-gray-700 truncate">{k.text}</span>
                          </label>
                        ))
                      )}
                   </div>
                </div>
             </div>

             <div className="p-5 bg-white border-t flex items-center justify-between gap-4">
                <div className="flex gap-2">
                  <button onClick={createGroup} className="flex items-center gap-2 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg text-[10px] font-black uppercase hover:bg-gray-200 transition-all border border-gray-200">
                    <FolderPlus size={14} /> Новая группа
                  </button>
                  {selection.size > 0 && (
                    <div className="relative group">
                      <button className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-lg text-[10px] font-black uppercase hover:bg-indigo-100 transition-all border border-indigo-200">
                         Переместить <ChevronDown size={12} />
                      </button>
                      <div className="absolute bottom-full mb-2 left-0 w-48 bg-white border border-gray-200 rounded-xl shadow-2xl hidden group-hover:block p-2 animate-in slide-in-from-bottom-2">
                        {currentProject?.groups.map(g => (
                          <button key={g.id} onClick={() => moveToGroup(g.id)} className="w-full text-left p-2 text-[10px] font-bold text-gray-600 hover:bg-indigo-50 rounded-lg transition-colors truncate">
                            {g.name}
                          </button>
                        ))}
                        <button onClick={() => moveToGroup("")} className="w-full text-left p-2 text-[10px] font-bold text-gray-400 hover:bg-gray-50 rounded-lg transition-colors border-t border-gray-100 mt-1">
                          Без группы
                        </button>
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-2">
                  <div className="text-right mr-2">
                    <span className="text-[9px] text-gray-400 uppercase font-black block leading-tight">Выбрано</span>
                    <span className="text-base font-black text-red-600 leading-none">{selection.size}</span>
                  </div>
                  <button 
                    disabled={selection.size === 0}
                    onClick={() => moveKeywords('parsed')} 
                    className="flex items-center gap-2 px-5 py-2.5 bg-green-600 text-white rounded-xl text-[10px] font-black uppercase tracking-wider shadow-lg shadow-green-100 hover:bg-green-700 transition-all disabled:bg-gray-200 disabled:shadow-none"
                  >
                    <Undo2 size={14} /> Восстановить
                  </button>
                  <button 
                    disabled={selection.size === 0}
                    onClick={() => moveKeywords('trash')} 
                    className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-wider shadow-lg shadow-slate-100 hover:bg-black transition-all disabled:bg-gray-200 disabled:shadow-none"
                  >
                    <Trash2 size={14} /> В корзину
                  </button>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Word Analysis Modal - ULTRA COMPACT */}
      {showAnalysis && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-xl h-[80vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95">
             <div className="p-4 border-b flex justify-between items-center bg-indigo-50/50">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-indigo-600 text-white rounded-lg"><Scissors size={18} /></div>
                   <div>
                      <h2 className="text-sm font-black text-indigo-900 leading-tight uppercase">Анализ по словам</h2>
                      <p className="text-[9px] text-indigo-400 uppercase font-bold tracking-widest">Разбивка фраз на части</p>
                   </div>
                </div>
                <button onClick={() => { setShowAnalysis(false); setSelection(new Set()); }} className="p-1.5 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-full transition-colors"><X size={20} /></button>
             </div>

             <div className="flex-1 overflow-y-auto p-3 space-y-1 bg-gray-50/30">
                {wordAnalysisMap.map(([word, ids]) => {
                  const isExpanded = expandedWords.has(word);
                  const allInSelection = ids.every(id => selection.has(id));
                  const someInSelection = ids.some(id => selection.has(id));

                  return (
                    <div key={word} className="bg-white rounded border border-gray-200 transition-all">
                      <div className="flex items-center p-2 hover:bg-gray-50 group">
                        <input 
                          type="checkbox" 
                          checked={allInSelection}
                          ref={el => el && (el.indeterminate = someInSelection && !allInSelection)}
                          onChange={() => toggleWordSelection(ids)}
                          className="mx-2 h-4 w-4 rounded border-gray-300 text-indigo-600 cursor-pointer"
                        />
                        <div className="flex-1 flex items-center justify-between cursor-pointer py-1" onClick={() => toggleWordExpand(word)}>
                          <div className="flex flex-col">
                            <span className="text-xs font-bold text-slate-700 capitalize">{word}</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{ids.length} вхождений</span>
                          </div>
                          {isExpanded ? <ChevronDown size={14} className="text-slate-400" /> : <ChevronRight size={14} className="text-slate-400" />}
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-10 py-2 bg-gray-50/80 border-t border-gray-100 space-y-0.5">
                          {ids.map(id => {
                            const k = currentProject?.keywords.find(item => item.id === id);
                            if (!k) return null;
                            return (
                              <label key={id} className="flex items-center gap-2 py-0.5 group cursor-pointer">
                                <input 
                                  type="checkbox" 
                                  checked={selection.has(id)} 
                                  onChange={() => toggleSelect(id)} 
                                  className="h-3 w-3 text-indigo-500 rounded border-gray-300" 
                                />
                                <span className="text-[10px] text-slate-500 truncate group-hover:text-indigo-600">{k.text}</span>
                              </label>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
             </div>

             <div className="p-4 bg-white border-t flex items-center justify-between">
                <div className="flex flex-col">
                  <span className="text-[9px] text-slate-400 uppercase font-black">ВЫБРАНО ЗАПРОСОВ</span>
                  <span className="text-lg font-black text-indigo-600 leading-none">{selection.size}</span>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => moveKeywords('negative')} className="px-6 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-wider shadow-lg shadow-red-100">В минус</button>
                  <button onClick={() => moveKeywords('trash')} className="px-6 py-2 bg-slate-900 text-white rounded-lg text-[10px] font-black uppercase tracking-wider">Удалить</button>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Trash Modal */}
      {showTrash && (
        <div className="fixed inset-0 bg-black/60 z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[60vh] flex flex-col shadow-2xl">
            <div className="p-4 border-b flex justify-between items-center">
              <h2 className="text-sm font-black uppercase">Корзина ({currentProject?.keywords.filter(k => k.status === 'trash').length})</h2>
              <button onClick={() => setShowTrash(false)}><X size={20}/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-1">
               {currentProject?.keywords.filter(k => k.status === 'trash').map(k => (
                 <div key={k.id} className="text-[10px] p-2 bg-gray-50 rounded flex justify-between">
                   <span>{k.text}</span>
                   <button onClick={() => {
                     updateProject(p => ({
                       ...p,
                       keywords: p.keywords.map(kw => kw.id === k.id ? { ...kw, status: 'parsed' } : kw)
                     }))
                   }} className="text-blue-600 font-bold hover:underline">Вернуть</button>
                 </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {/* Bulk Add Modal */}
      {showBulkAdd && (
        <div className="fixed inset-0 bg-black/60 z-[70] flex items-center justify-center p-4">
           <div className="bg-white rounded-2xl w-full max-w-md p-6 flex flex-col shadow-2xl">
              <h2 className="text-lg font-bold mb-4">Массовая загрузка</h2>
              <textarea value={bulkInput} onChange={(e) => setBulkInput(e.target.value)} placeholder="По одному слову на строку..." className="w-full h-48 p-3 border rounded text-xs mb-4 outline-none font-mono" />
              <button onClick={handleBulkAddAction} className="w-full py-3 bg-blue-600 text-white rounded font-bold uppercase text-xs">Загрузить</button>
              <button onClick={() => setShowBulkAdd(false)} className="mt-2 text-xs text-gray-400 text-center hover:underline">Отмена</button>
           </div>
        </div>
      )}

      {/* Project Manager */}
      {showProjectManager && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-sm overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-gray-50">
              <h2 className="text-xs font-black uppercase">Проекты</h2>
              <button onClick={() => setShowProjectManager(false)}><X size={18}/></button>
            </div>
            <div className="p-2 max-h-60 overflow-y-auto space-y-1">
              {projects.map(p => (
                <div key={p.id} onClick={() => { setCurrentProjectId(p.id); setShowProjectManager(false); }} className={`p-3 rounded text-xs font-bold cursor-pointer transition-all ${currentProjectId === p.id ? 'bg-blue-50 border-blue-200 border' : 'hover:bg-gray-100 border-transparent border'}`}>
                  {p.name} <span className="text-[9px] text-blue-400 ml-2">({p.keywords.length})</span>
                </div>
              ))}
            </div>
            <div className="p-4 border-t bg-gray-50">
              <button onClick={() => createProject()} className="w-full py-2 bg-blue-600 text-white rounded text-xs font-bold uppercase">+ Создать проект</button>
            </div>
          </div>
        </div>
      )}

      {/* Seeds Modal */}
      {showSelected && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl w-full max-w-lg h-[70vh] flex flex-col shadow-2xl overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-blue-50/40 font-black text-xs uppercase">Семена для анализа</div>
            <div className="flex-1 overflow-y-auto p-2">
                 {currentProject?.keywords.filter(k => k.status === 'selected').map(k => (
                   <label key={k.id} className="flex items-center p-2 hover:bg-gray-50 rounded">
                     <input type="checkbox" checked={selection.has(k.id)} onChange={() => toggleSelect(k.id)} className="h-4 w-4 mr-3" />
                     <span className="text-xs font-bold">{k.text}</span>
                   </label>
                 ))}
            </div>
            <div className="p-4 border-t bg-gray-50">
               <button onClick={startAnalysis} disabled={loading || selection.size === 0} className="w-full py-3 bg-green-600 text-white rounded font-black text-xs uppercase flex items-center justify-center gap-2">
                  <Play size={14} fill="currentColor" /> Запустить расширение
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

