                  const isExpanded = expandedWords.has(word);
                  const allInSelection = ids.every(id => selection.has(id));
                  const someInSelection = ids.some(id => selection.has(id));

                  return (
                    <div key={word} className="bg-white rounded-2xl border border-slate-200 transition-all overflow-hidden shadow-sm">
