                            <span className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{ids.length} вхождений</span>
                          </div>
                          {isExpanded ? <ChevronDown size={18} className="text-slate-400" /> : <ChevronRight size={18} className="text-slate-400" />}
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-14 py-3 bg-slate-50 border-t border-slate-100 space-y-1">
                          {ids.map(id => {
                            const k = currentProject?.keywords.find(item => item.id === id);
                            if (!k) return null;
                            return (
                              <label key={id} className="flex items-center gap-3 py-1.5 group cursor-pointer border-b border-white last:border-0">
                                <input type="checkbox" checked={selection.has(id)} onChange={() => toggleSelect(id)} className="h-4 w-4 text-indigo-500 rounded-md border-slate-300" />
                                <span className="text-[11px] font-bold text-slate-600 group-hover:text-indigo-600 truncate transition-colors">{k.text}</span>
                              </label>
                            );
                          })}
