             <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-red-50/20">
                <div className="flex items-center gap-4">
                   <div className="p-3 bg-red-600 text-white rounded-2xl shadow-xl shadow-red-100"><MinusSquare size={24} /></div>
                   <div>
                      <h2 className="text-xl font-black text-slate-900 leading-tight uppercase tracking-tight">Минус-слова проекта</h2>
