                        />
                        <div className="flex-1 flex items-center justify-between cursor-pointer py-0.5" onClick={() => toggleWordExpand(word)}>
                          <div className="flex flex-col">
                            <span className="text-sm font-black text-slate-700 capitalize tracking-tight">{word}</span>
