                          </div>
                          {isExpanded ? <ChevronDown size={18} className="text-slate-400" /> : <ChevronRight size={18} className="text-slate-400" />}
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-14 py-1.5 bg-slate-50 border-t border-slate-100 space-y-0.5">
                          {ids.map(id => {
                            const k = currentProject?.keywords.find(item => item.id === id);
                            if (!k) return null;
                            return (
                              <div key={id} className="flex items-center gap-3 py-1 border-b border-white last:border-0 opacity-70">
                                <span className="text-[11px] font-bold text-slate-600 truncate">{k.text}</span>
                              </div>
                            );
